import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserStatus {
  PENDING = 'PENDING',
  ACTIVE = 'ACTIVE',
  BLOCKED = 'BLOCKED'
}

export enum Role {
  USER = 'USER',
  APPROVER = 'APPROVER',
  ADMIN = 'ADMIN'
}

export enum Capability {
  RECEIVE_ONLY = 'RECEIVE_ONLY',
  LEADERSHIP = 'LEADERSHIP',
  APPROVE_PURCHASES = 'APPROVE_PURCHASES',
  ADMIN = 'ADMIN'
}

export interface User {
  id: string;
  corporateId: string;
  name: string;
  passwordHash: string;
  status: UserStatus;
  roles: Role[];
  capabilities: Capability[];
  createdAt: string;
}

export interface Wallet {
  userId: string;
  balance: number;
}

export enum TransactionType {
  CREDIT = 'CREDIT',
  DEBIT = 'DEBIT'
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  fromUserId: string | 'SYSTEM';
  toUserId: string;
  reason: string;
  category: string;
  createdAt: string;
  createdBy: string;
}

export interface RewardItem {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  cost: number;
  stock: number;
  category: string;
  isActive: boolean;
}

export enum OrderStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  ADJUSTMENT_REQUESTED = 'ADJUSTMENT_REQUESTED',
  DELIVERED = 'DELIVERED'
}

export interface Order {
  id: string;
  userId: string;
  status: OrderStatus;
  totalCost: number;
  createdAt: string;
  updatedAt: string;
  items: OrderItem[];
  note?: string;
  approverId?: string;
}

export interface OrderItem {
  itemId: string;
  qty: number;
  costEach: number;
}

export interface AuditLog {
  id: string;
  actorUserId: string;
  action: string;
  entityType: string;
  entityId: string;
  details: any;
  createdAt: string;
}

import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, TransactionType,
  RewardItem, Order, OrderStatus, AuditLog 
} from './types';

const STORAGE_KEY = 'tampinhas_db';

interface DB {
  users: User[];
  wallets: Wallet[];
  transactions: Transaction[];
  rewardItems: RewardItem[];
  orders: Order[];
  auditLogs: AuditLog[];
  config: {
    currencyName: string;
    conversionRate: number;
    donationLimit: number;
  };
}

const INITIAL_DB: DB = {
  users: [
    {
      id: 'admin-uuid',
      corporateId: 'admin',
      name: 'Administrador Sistema',
      passwordHash: '1234', // In a real app, this would be hashed
      status: UserStatus.ACTIVE,
      roles: [Role.ADMIN],
      capabilities: [Capability.ADMIN],
      createdAt: new Date().toISOString()
    }
  ],
  wallets: [
    { userId: 'admin-uuid', balance: 1000 }
  ],
  transactions: [],
  rewardItems: [
    { id: '1', name: 'Boné', description: 'Boné bordado exclusivo', imageUrl: 'https://picsum.photos/400/300?random=1', cost: 8, stock: 10, category: 'Vestuário', isActive: true },
    { id: '2', name: 'Camiseta', description: 'Camiseta algodão premium', imageUrl: 'https://picsum.photos/400/300?random=2', cost: 12, stock: 8, category: 'Vestuário', isActive: true },
    { id: '3', name: 'Fone de Ouvido', description: 'Fone bluetooth alta fidelidade', imageUrl: 'https://picsum.photos/400/300?random=3', cost: 25, stock: 5, category: 'Eletrônicos', isActive: true },
    { id: '4', name: 'Garrafa Térmica', description: 'Garrafa 500ml inox', imageUrl: 'https://picsum.photos/400/300?random=4', cost: 15, stock: 6, category: 'Acessórios', isActive: true },
    { id: '5', name: 'Mochila', description: 'Mochila reforçada para notebook', imageUrl: 'https://picsum.photos/400/300?random=5', cost: 30, stock: 3, category: 'Acessórios', isActive: true }
  ],
  orders: [],
  auditLogs: [],
  config: {
    currencyName: 'tampinhas',
    conversionRate: 1,
    donationLimit: 100
  }
};

export const getDB = (): DB => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DB));
    return INITIAL_DB;
  }
  return JSON.parse(data);
};

export const saveDB = (db: DB) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const addAuditLog = (db: DB, log: Omit<AuditLog, 'id' | 'createdAt'>) => {
  const newLog: AuditLog = {
    ...log,
    id: Math.random().toString(36).substr(2, 9),
    createdAt: new Date().toISOString()
  };
  db.auditLogs.unshift(newLog);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, 
  RewardItem, Order, OrderStatus, TransactionType 
} from './types';
import { getDB, saveDB, addAuditLog } from './store';

// Pages
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Store from './pages/Store';
import MyOrders from './pages/MyOrders';
import Leadership from './pages/Leadership';
import Approvals from './pages/Approvals';
import Admin from './pages/Admin';
import Sidebar from './components/Sidebar';
import Topbar from './components/Topbar';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');
  const [db, setDb] = useState(getDB());

  // Check session on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('current_user');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      // Re-verify against DB
      const dbUser = db.users.find(u => u.id === parsed.id);
      if (dbUser && dbUser.status === UserStatus.ACTIVE) {
        setUser(dbUser);
        setView('DASHBOARD');
      } else {
        localStorage.removeItem('current_user');
      }
    }
  }, [db.users]);

  const handleLogin = (u: User) => {
    if (u.status !== UserStatus.ACTIVE) {
      alert('Sua conta está aguardando liberação do administrador ou está bloqueada.');
      return;
    }
    setUser(u);
    localStorage.setItem('current_user', JSON.stringify(u));
    setView('DASHBOARD');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user');
    setView('LOGIN');
  };

  const refreshDB = () => setDb(getDB());

  const userWallet = useMemo(() => {
    if (!user) return { userId: '', balance: 0 };
    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0 };
  }, [user, db.wallets]);

  if (view === 'LOGIN') return <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} />;
  if (view === 'REGISTER') return <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} />;

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        currentView={view} 
        setView={setView} 
        capabilities={user?.capabilities || []} 
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Topbar 
          user={user} 
          balance={userWallet.balance} 
          onLogout={handleLogout} 
        />

        <main className="p-4 md:p-8 overflow-y-auto">
          {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
          {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} />}
          {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
          {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} />}
          {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} />}
          {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} />}
        </main>
      </div>
    </div>
  );
};

export default App;

