export default Login;

import React, { useState } from 'react';
import { UserStatus, Role, Capability } from '../types';
import { saveDB } from '../store';

interface RegisterProps {
  onGoToLogin: () => void;
  db: any;
  onRefreshDB: () => void;
}

const Register: React.FC<RegisterProps> = ({ onGoToLogin, db, onRefreshDB }) => {
  const [formData, setFormData] = useState({
    corporateId: '',
    name: '',
    password: '',
    confirmPassword: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      alert('As senhas não coincidem!');
      return;
    }

    if (db.users.some((u: any) => u.corporateId === formData.corporateId)) {
      alert('Este ID já está cadastrado!');
      return;
    }

    const newUser = {
      id: Math.random().toString(36).substr(2, 9),
      corporateId: formData.corporateId,
      name: formData.name,
      passwordHash: formData.password,
      status: UserStatus.PENDING,
      roles: [Role.USER],
      capabilities: [Capability.RECEIVE_ONLY],
      createdAt: new Date().toISOString()
    };

    db.users.push(newUser);
    // Create empty wallet
    db.wallets.push({ userId: newUser.id, balance: 0 });

    saveDB(db);
    onRefreshDB();
    alert('Cadastro realizado com sucesso! Aguarde a aprovação do administrador para acessar.');
    onGoToLogin();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-8">
        <h2 className="text-2xl font-bold text-slate-900 mb-2">Criar nova conta</h2>
        <p className="text-slate-500 mb-8">Preencha seus dados corporativos para começar.</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Nome Completo</label>
            <input 
              type="text" required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">ID Corporativo</label>
            <input 
              type="text" required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl"
              value={formData.corporateId}
              onChange={e => setFormData({...formData, corporateId: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Senha</label>
            <input 
              type="password" required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl"
              value={formData.password}
              onChange={e => setFormData({...formData, password: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">Confirmar Senha</label>
            <input 
              type="password" required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl"
              value={formData.confirmPassword}
              onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
            />
          </div>

          <button 
            type="submit"
            className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all mt-4"
          >
            Finalizar Cadastro
          </button>
        </form>

        <button 
          onClick={onGoToLogin}
          className="w-full mt-4 text-slate-500 font-medium hover:text-slate-800"
        >
          Voltar para o Login
        </button>
      </div>
    </div>
  );
};

export default Register;

import React, { useState } from 'react';
import { User, RewardItem, OrderStatus, TransactionType } from '../types';
import { saveDB, addAuditLog } from '../store';

interface StoreProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Store: React.FC<StoreProps> = ({ user, db, onRefreshDB }) => {
  const [filter, setFilter] = useState('');
  const [category, setCategory] = useState('Todas');
  const categories = ['Todas', ...Array.from(new Set(db.rewardItems.map((i: any) => i.category)))];
  const wallet = db.wallets.find((w: any) => w.userId === user.id);

  const filteredItems = db.rewardItems.filter((item: RewardItem) => {
    const matchesSearch = item.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCategory = category === 'Todas' || item.category === category;
    return matchesSearch && matchesCategory && item.isActive;
  });

  const handlePurchase = (item: RewardItem) => {
    if (wallet.balance < item.cost) {
      alert('Saldo insuficiente!');
      return;
    }
    if (item.stock <= 0) {
      alert('Item fora de estoque!');
      return;
    }

    if (!confirm(`Deseja resgatar "${item.name}" por ${item.cost} tampinhas?`)) return;

    // Create Order
    const newOrder = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      status: OrderStatus.PENDING,
      totalCost: item.cost,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      items: [{ itemId: item.id, qty: 1, costEach: item.cost }]
    };

    db.orders.push(newOrder);

    // Audit Log for the request
    addAuditLog(db, {
      actorUserId: user.id,
      action: 'ORDER_REQUEST',
      entityType: 'ORDER',
      entityId: newOrder.id,
      details: { item: item.name, cost: item.cost }
    });

    saveDB(db);
    onRefreshDB();
    alert('Solicitação de resgate enviada! Acompanhe em "Meus Pedidos".');
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Loja de Brindes</h1>
          <p className="text-slate-500">Use suas tampinhas para resgatar recompensas exclusivas.</p>
        </div>
        <div className="bg-indigo-600 text-white p-4 rounded-2xl flex items-center gap-4 shadow-lg shadow-indigo-100">
           <i className="fa-solid fa-wallet text-2xl"></i>
           <div>
             <p className="text-xs uppercase font-bold opacity-75">Seu Saldo</p>
             <p className="text-2xl font-black">{wallet?.balance || 0} <span className="text-sm font-normal">tampinhas</span></p>
           </div>
        </div>
      </header>

      <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
        <div className="relative w-full md:w-96">
          <i className="fa-solid fa-magnifying-glass absolute left-4 top-3.5 text-slate-400"></i>
          <input 
            type="text" 
            placeholder="Buscar brinde..."
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
          {categories.map(cat => (
            <button
              key={cat as string}
              onClick={() => setCategory(cat as string)}
              className={`px-4 py-2 rounded-full text-sm font-semibold whitespace-nowrap transition-all ${
                category === cat ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {cat as string}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {filteredItems.map((item: RewardItem) => (
          <div key={item.id} className="bg-white rounded-3xl overflow-hidden shadow-sm border border-slate-100 flex flex-col group hover:shadow-xl transition-all hover:-translate-y-1">
            <div className="relative h-48 bg-slate-200">
              <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
              <div className="absolute top-4 left-4">
                <span className="px-3 py-1 bg-white/90 backdrop-blur-md rounded-full text-xs font-bold text-slate-700 shadow-sm uppercase tracking-wider">
                  {item.category}
                </span>
              </div>
              {item.stock <= 0 && (
                <div className="absolute inset-0 bg-slate-900/60 flex items-center justify-center backdrop-blur-[2px]">
                  <span className="text-white font-bold text-lg uppercase tracking-widest border-2 border-white px-4 py-1 rotate-[-12deg]">Esgotado</span>
                </div>
              )}
            </div>

            <div className="p-6 flex-1 flex flex-col">
              <h3 className="text-lg font-bold text-slate-900 mb-1">{item.name}</h3>
              <p className="text-slate-500 text-sm mb-4 flex-1">{item.description}</p>

              <div className="flex items-center justify-between mt-4">
                <div className="flex items-center gap-1.5">
                  <span className="text-2xl font-black text-indigo-600">{item.cost}</span>
                  <i className="fa-solid fa-bottle-water text-indigo-400"></i>
                </div>
                <div className="text-right">
                  <p className="text-[10px] uppercase font-bold text-slate-400">Estoque</p>
                  <p className={`text-sm font-bold ${item.stock < 5 ? 'text-amber-500' : 'text-slate-600'}`}>{item.stock} unidades</p>
                </div>
              </div>

              <button 
                disabled={item.stock <= 0 || wallet.balance < item.cost}
                onClick={() => handlePurchase(item)}
                className={`mt-6 w-full py-3 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${
                  item.stock <= 0 || wallet.balance < item.cost
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg shadow-indigo-100 active:scale-95'
                }`}
              >
                {wallet.balance < item.cost ? 'Saldo Insuficiente' : 'Resgatar Agora'}
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

