import React, { useState } from 'react';
import { User, TransactionType, Transaction, Capability } from '../types';
import { saveDB, addAuditLog } from '../store';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('Reconhecimento');

  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) {
      alert('Quantidade deve ser maior que zero!');
      return;
    }
    if (!recipientId) {
      alert('Selecione um destinatário!');
      return;
    }

    const recipient = db.users.find((u: User) => u.id === recipientId);
    if (!recipient) return;

    if (!confirm(`Deseja dar ${amount} tampinhas para ${recipient.name}?`)) return;

    // Credit Transaction
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: TransactionType.CREDIT,
      amount: amount,
      fromUserId: user.id,
      toUserId: recipientId,
      reason: reason,
      category: category,
      createdAt: new Date().toISOString(),
      createdBy: user.id
    };

    db.transactions.push(tx);

    // Update Recipient Wallet
    const wallet = db.wallets.find((w: any) => w.userId === recipientId);
    if (wallet) {
      wallet.balance += amount;
    } else {
      db.wallets.push({ userId: recipientId, balance: amount });
    }

    // Audit Log
    addAuditLog(db, {
      actorUserId: user.id,
      action: 'GIFT_TAMPINHAS',
      entityType: 'TRANSACTION',
      entityId: tx.id,
      details: { to: recipient.name, amount, reason }
    });

    saveDB(db);
    onRefreshDB();

    alert(`Sucesso! ${amount} tampinhas enviadas para ${recipient.name}.`);
    setAmount(0);
    setReason('');
    setRecipientId('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Dar Tampinhas</h1>
        <p className="text-slate-500">Reconheça o esforço e os resultados da sua equipe.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <form onSubmit={handleSubmit} className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Destinatário</label>
            <select 
              required
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl appearance-none"
              value={recipientId}
              onChange={e => setRecipientId(e.target.value)}
            >
              <option value="">Selecione um colaborador...</option>
              {activeUsers.map((u: User) => (
                <option key={u.id} value={u.id}>{u.name} ({u.corporateId})</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Quantidade</label>
              <input 
                type="number" required min="1"
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-indigo-600"
                value={amount}
                onChange={e => setAmount(Number(e.target.value))}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Categoria</label>
              <select 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl"
                value={category}
                onChange={e => setCategory(e.target.value)}
              >
                <option>Reconhecimento</option>
                <option>Meta Batida</option>
                <option>Destaque do Mês</option>
                <option>Inovação</option>
                <option>Cultura</option>
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Justificativa</label>
            <textarea 
              required rows={4}
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl"
              placeholder="Descreva por que este colaborador está sendo reconhecido..."
              value={reason}
              onChange={e => setReason(e.target.value)}
            ></textarea>
          </div>

          <button 
            type="submit"
            className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-emerald-700 shadow-lg shadow-emerald-100 transition-all flex items-center justify-center gap-2"
          >
            <i className="fa-solid fa-paper-plane"></i>
            Confirmar Envio
          </button>
        </form>

        <div className="space-y-6">
          <div className="bg-indigo-600 rounded-3xl p-8 text-white">
            <h4 className="font-bold text-xl mb-2">Dica de Liderança</h4>
            <p className="opacity-90">Elogios públicos e reconhecimentos imediatos aumentam o engajamento em até 40%. Não deixe para depois!</p>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
            <h4 className="font-bold text-slate-900 mb-4">Regras de Doação</h4>
            <ul className="space-y-3 text-sm text-slate-600">
              <li className="flex gap-3">
                <i className="fa-solid fa-circle-check text-emerald-500 mt-0.5"></i>
                <span>Somente valores positivos.</span>
              </li>
              <li className="flex gap-3">
                <i className="fa-solid fa-circle-check text-emerald-500 mt-0.5"></i>
                <span>Justificativa é obrigatória para auditoria.</span>
              </li>
              <li className="flex gap-3">
                <i className="fa-solid fa-circle-check text-emerald-500 mt-0.5"></i>
                <span>Limite mensal sugerido: 500 tampinhas.</span>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

