import React, { useState } from 'react';
import { User, Order, OrderStatus, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog } from '../store';

interface ApprovalsProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Approvals: React.FC<ApprovalsProps> = ({ user, db, onRefreshDB }) => {
  const [activeTab, setActiveTab] = useState<OrderStatus>(OrderStatus.PENDING);
  const [note, setNote] = useState('');

  const filteredOrders = db.orders.filter((o: Order) => {
    if (activeTab === OrderStatus.PENDING) return o.status === OrderStatus.PENDING;
    return o.status !== OrderStatus.PENDING;
  }).sort((a: any, b: any) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const processDecision = (order: Order, decision: OrderStatus) => {
    if (decision !== OrderStatus.APPROVED && !note) {
      alert('É obrigatório adicionar uma justificativa para reprovar ou pedir ajuste.');
      return;
    }

    const requester = db.users.find((u: User) => u.id === order.userId);
    const requesterWallet = db.wallets.find((w: any) => w.userId === order.userId);

    // Check constraints if approving
    if (decision === OrderStatus.APPROVED) {
      if (requesterWallet.balance < order.totalCost) {
        alert('O usuário não tem mais saldo suficiente para esta aprovação.');
        return;
      }

      // Check stock
      for (const oi of order.items) {
        const item = db.rewardItems.find((ri: any) => ri.id === oi.itemId);
        if (item.stock < oi.qty) {
          alert(`Estoque insuficiente para o item: ${item.name}`);
          return;
        }
      }

      // ATOMIC TRANSACTION: Debit balance + Lower stock
      requesterWallet.balance -= order.totalCost;

      const debitTx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.DEBIT,
        amount: order.totalCost,
        fromUserId: requester.id,
        toUserId: 'REWARD_STORE',
        reason: `Resgate de brinde aprovado (Pedido #${order.id})`,
        category: 'Resgate',
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };
      db.transactions.push(debitTx);

      for (const oi of order.items) {
        const item = db.rewardItems.find((ri: any) => ri.id === oi.itemId);
        item.stock -= oi.qty;
      }
    }

    // Update order
    order.status = decision;
    order.note = note;
    order.approverId = user.id;
    order.updatedAt = new Date().toISOString();

    // Audit Log
    addAuditLog(db, {
      actorUserId: user.id,
      action: `ORDER_${decision}`,
      entityType: 'ORDER',
      entityId: order.id,
      details: { note, user: requester.name }
    });

    saveDB(db);
    onRefreshDB();
    setNote('');
    alert('Decisão registrada com sucesso!');
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Painel de Aprovações</h1>
        <p className="text-slate-500">Analise e decida sobre as solicitações pendentes.</p>
      </header>

      <div className="flex gap-2 bg-slate-100 p-1.5 rounded-2xl w-fit">
        <button 
          onClick={() => setActiveTab(OrderStatus.PENDING)}
          className={`px-6 py-2 rounded-xl font-bold transition-all ${activeTab === OrderStatus.PENDING ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
        >
          Pendentes
        </button>
        <button 
          onClick={() => setActiveTab(OrderStatus.APPROVED)}
          className={`px-6 py-2 rounded-xl font-bold transition-all ${activeTab !== OrderStatus.PENDING ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
        >
          Histórico
        </button>
      </div>

      <div className="grid gap-6">
        {filteredOrders.length === 0 ? (
          <div className="bg-white p-16 rounded-3xl border border-dashed border-slate-300 text-center">
            <p className="text-slate-500">Nenhuma solicitação encontrada nesta categoria.</p>
          </div>
        ) : (
          filteredOrders.map((order: Order) => {
            const requester = db.users.find((u: any) => u.id === order.userId);
            const wallet = db.wallets.find((w: any) => w.userId === order.userId);
            return (
              <div key={order.id} className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-8">
                <div className="flex-1 space-y-6">
                  <div className="flex items-start justify-between">
                    <div>
                      <h4 className="text-xl font-bold text-slate-900">Solicitação #{order.id}</h4>
                      <p className="text-sm text-slate-500">Colaborador: <span className="font-bold text-slate-700">{requester?.name}</span> ({requester?.corporateId})</p>
                      <p className="text-sm text-slate-500">Data: {new Date(order.createdAt).toLocaleString('pt-BR')}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-xs uppercase font-bold text-slate-400">Custo Total</p>
                      <p className="text-2xl font-black text-indigo-600">{order.totalCost} tampinhas</p>
                      <p className="text-xs text-slate-500">Saldo atual: {wallet?.balance} tampinhas</p>
                    </div>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <p className="text-xs font-bold text-slate-400 uppercase mb-3 tracking-widest">Resumo do Pedido</p>
                    <div className="space-y-3">
                      {order.items.map((oi, idx) => {
                        const item = db.rewardItems.find((ri: any) => ri.id === oi.itemId);
                        return (
                          <div key={idx} className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                              <img src={item?.imageUrl} className="w-8 h-8 rounded-lg object-cover" />
                              <span className="text-sm font-semibold text-slate-800">{item?.name}</span>
                              <span className="text-xs text-slate-500">x{oi.qty}</span>
                            </div>
                            <span className="text-sm font-bold text-slate-700">{oi.costEach * oi.qty} t.</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="w-full md:w-80 flex flex-col justify-between">
                  {order.status === OrderStatus.PENDING ? (
                    <div className="space-y-4">
                      <label className="block text-sm font-semibold text-slate-700">Observações / Motivo</label>
                      <textarea 
                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm"
                        placeholder="Obrigatório para reprovação ou pedido de ajuste..."
                        rows={3}
                        value={note}
                        onChange={e => setNote(e.target.value)}
                      ></textarea>
                      <div className="grid grid-cols-2 gap-2">
                        <button 
                          onClick={() => processDecision(order, OrderStatus.REJECTED)}
                          className="py-3 bg-white border border-rose-200 text-rose-600 rounded-xl font-bold hover:bg-rose-50 transition-all text-sm"
                        >
                          Reprovar
                        </button>
                        <button 
                          onClick={() => processDecision(order, OrderStatus.ADJUSTMENT_REQUESTED)}
                          className="py-3 bg-white border border-blue-200 text-blue-600 rounded-xl font-bold hover:bg-blue-50 transition-all text-sm"
                        >
                          Ajuste
                        </button>
                      </div>
                      <button 
                        onClick={() => processDecision(order, OrderStatus.APPROVED)}
                        className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 shadow-lg shadow-emerald-50 transition-all flex items-center justify-center gap-2"
                      >
                        <i className="fa-solid fa-check"></i>
                        Aprovar Resgate
                      </button>
                    </div>
                  ) : (
                    <div className="h-full flex flex-col justify-center items-center p-6 bg-slate-50 rounded-3xl border border-slate-100 border-dashed">
                      <div className={`text-center space-y-2`}>
                        <p className="text-xs uppercase font-bold text-slate-400">Status Final</p>
                        <p className={`text-xl font-black uppercase tracking-widest`}>{order.status}</p>
                        <p className="text-xs text-slate-500">Decidido em {new Date(order.updatedAt).toLocaleDateString()}</p>
                        {order.note && <p className="mt-4 text-xs italic text-slate-600 bg-white p-2 rounded-lg border border-slate-100">"{order.note}"</p>}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default Approvals;

import React, { useState } from 'react';
import { User, UserStatus, Role, Capability, RewardItem } from '../types';
import { saveDB, addAuditLog } from '../store';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS' | 'CONFIG' | 'LOGS'>('USERS');

  const updateUserStatus = (u: User, status: UserStatus) => {
    u.status = status;
    addAuditLog(db, {
      actorUserId: user.id,
      action: 'USER_STATUS_CHANGE',
      entityType: 'USER',
      entityId: u.id,
      details: { status }
    });
    saveDB(db);
    onRefreshDB();
  };

  const toggleCapability = (u: User, cap: Capability) => {
    if (u.capabilities.includes(cap)) {
      u.capabilities = u.capabilities.filter(c => c !== cap);
    } else {
      u.capabilities.push(cap);
    }
    saveDB(db);
    onRefreshDB();
  };

  const handleCreateItem = () => {
    const name = prompt('Nome do brinde:');
    if (!name) return;
    const cost = Number(prompt('Custo em tampinhas:'));
    const stock = Number(prompt('Estoque inicial:'));
    const category = prompt('Categoria:', 'Geral') || 'Geral';

    const newItem: RewardItem = {
      id: Math.random().toString(36).substr(2, 9),
