          </div>
          <h1 className="text-2xl font-bold text-slate-900">Bem-vindo de volta!</h1>
          <p className="text-slate-500">Gestão de Reconhecimentos Digital</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
