import React, { useState } from 'react';
import { User, TransactionType, Transaction, Capability } from '../types';
import { saveDB, addAuditLog } from '../store';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('Reconhecimento');

  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) {
      alert('Quantidade deve ser maior que zero!');
      return;
    }
    if (!recipientId) {
      alert('Selecione um destinatário!');
      return;
    }

    const recipient = db.users.find((u: User) => u.id === recipientId);
    if (!recipient) return;

    if (!confirm(`Deseja dar ${amount} tampinhas para ${recipient.name}?`)) return;

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: TransactionType.CREDIT,
      amount: amount,
      fromUserId: user.id,
      toUserId: recipientId,
      reason: reason,
      category: category,
      createdAt: new Date().toISOString(),
      createdBy: user.id
    };

    db.transactions.push(tx);
    const wallet = db.wallets.find((w: any) => w.userId === recipientId);
    if (wallet) {
      wallet.balance += amount;
    } else {
      db.wallets.push({ userId: recipientId, balance: amount });
    }

    addAuditLog(db, {
      actorUserId: user.id,
      action: 'GIFT_TAMPINHAS',
      entityType: 'TRANSACTION',
      entityId: tx.id,
      details: { to: recipient.name, amount, reason }
    });

    saveDB(db);
    onRefreshDB();

    alert(`Sucesso! ${amount} tampinhas enviadas para ${recipient.name}.`);
    setAmount(0);
    setReason('');
    setRecipientId('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <header>
        <p className="text-yellow-500 font-bold text-xs uppercase tracking-widest mb-1">Cultura de Reconhecimento</p>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Dar Tampinhas</h1>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
        <form onSubmit={handleSubmit} className="lg:col-span-3 bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 space-y-6">
          <div className="space-y-2">
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Destinatário</label>
            <select 
              required
              className="w-full p-4 bg-black border border-slate-800 text-white rounded-2xl appearance-none focus:border-yellow-500 outline-none"
              value={recipientId}
              onChange={e => setRecipientId(e.target.value)}
            >
              <option value="">Selecione um colaborador...</option>
              {activeUsers.map((u: User) => (
                <option key={u.id} value={u.id}>{u.name.toUpperCase()} ({u.corporateId})</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Quantidade</label>
              <input 
                type="number" required min="1"
                className="w-full p-4 bg-black border border-slate-800 text-yellow-500 font-black rounded-2xl focus:border-yellow-500 outline-none"
                value={amount}
                onChange={e => setAmount(Number(e.target.value))}
              />
            </div>
            <div className="space-y-2">
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Categoria</label>
              <select 
                className="w-full p-4 bg-black border border-slate-800 text-white rounded-2xl focus:border-yellow-500 outline-none"
                value={category}
                onChange={e => setCategory(e.target.value)}
              >
                <option>Reconhecimento</option>
                <option>Meta Batida</option>
                <option>Destaque do Mês</option>
                <option>Cultura</option>
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Justificativa</label>
            <textarea 
              required rows={4}
              className="w-full p-4 bg-black border border-slate-800 text-white rounded-2xl focus:border-yellow-500 outline-none"
              placeholder="Por que este colaborador está sendo reconhecido?"
              value={reason}
              onChange={e => setReason(e.target.value)}
            ></textarea>
          </div>

          <button 
            type="submit"
            className="w-full bg-yellow-500 text-black py-4 rounded-2xl font-black text-lg uppercase tracking-widest hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/10 flex items-center justify-center gap-2"
          >
            <i className="fa-solid fa-bolt"></i>
            Confirmar Envio
          </button>
        </form>

        <div className="lg:col-span-2 space-y-6">
          <div className="bg-black border border-yellow-500/30 rounded-[2.5rem] p-8 text-white relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-5 text-6xl">
              <i className="fa-solid fa-quote-right"></i>
            </div>
            <h4 className="font-black text-xl uppercase italic text-yellow-500 mb-4 tracking-tighter">SUPPLY MOTIVAÇÃO</h4>
            <p className="text-slate-400 text-sm leading-relaxed italic">"Reconhecer o talento hoje é garantir o sucesso da Supply amanhã. Nada nos para!"</p>
          </div>

          <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800">
            <h4 className="font-black text-white uppercase tracking-widest text-xs mb-6 italic">Diretrizes</h4>
            <ul className="space-y-4 text-xs font-bold text-slate-500">
              <li className="flex gap-4">
                <span className="w-5 h-5 bg-yellow-500 text-black rounded-full flex items-center justify-center text-[10px]">1</span>
                <span>Valores apenas positivos.</span>
              </li>
              <li className="flex gap-4">
                <span className="w-5 h-5 bg-yellow-500 text-black rounded-full flex items-center justify-center text-[10px]">2</span>
                <span>Justificativa técnica ou cultural.</span>
              </li>
              <li className="flex gap-4">
                <span className="w-5 h-5 bg-yellow-500 text-black rounded-full flex items-center justify-center text-[10px]">3</span>
                <span>Limite sugerido: 500 por mês.</span>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

