import React, { useState } from 'react';
import { UserStatus, Role, Capability } from '../types';
import { saveDB } from '../store';

interface RegisterProps {
  onGoToLogin: () => void;
  db: any;
  onRefreshDB: () => void;
}

const Register: React.FC<RegisterProps> = ({ onGoToLogin, db, onRefreshDB }) => {
  const [formData, setFormData] = useState({
    corporateId: '',
    name: '',
    password: '',
    confirmPassword: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      alert('As senhas não coincidem!');
      return;
    }

    if (db.users.some((u: any) => u.corporateId === formData.corporateId)) {
      alert('Este ID já está cadastrado!');
      return;
    }

    const newUser = {
      id: Math.random().toString(36).substr(2, 9),
      corporateId: formData.corporateId,
      name: formData.name,
      passwordHash: formData.password,
      status: UserStatus.PENDING,
      roles: [Role.USER],
      capabilities: [Capability.RECEIVE_ONLY],
      createdAt: new Date().toISOString()
    };

    db.users.push(newUser);
    // Create empty wallet
    db.wallets.push({ userId: newUser.id, balance: 0 });

    saveDB(db);
    onRefreshDB();
    alert('Cadastro realizado com sucesso! Aguarde a aprovação do administrador para acessar.');
    onGoToLogin();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-black p-4 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-yellow-500/5 blur-[120px] rounded-full"></div>

      <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-xl border border-zinc-800 rounded-[3rem] shadow-2xl overflow-hidden p-10 animate-in fade-in zoom-in duration-500 relative z-10">
