import React, { useState } from 'react';
import { User, TransactionType, Transaction, Capability } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('Reconhecimento');

  // Filtrar apenas usuários ativos e que não sejam o próprio líder
  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = Number(amount);

    if (numAmount <= 0) {
      alert('Quantidade deve ser maior que zero!');
      return;
    }
    if (!recipientId) {
      alert('Selecione um destinatário!');
      return;
    }

    const currentDb = getDB(); // Pegar instância fresca do DB
    const recipient = currentDb.users.find((u: User) => u.id === recipientId);

    if (!recipient) {
      alert('Destinatário não encontrado!');
      return;
    }

    if (!confirm(`Deseja dar ${numAmount} tampinhas para ${recipient.name}?`)) return;

    // 1. Criar Transação
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: TransactionType.CREDIT,
      amount: numAmount,
      fromUserId: user.id,
      toUserId: recipientId,
      reason: reason,
      category: category,
      createdAt: new Date().toISOString(),
      createdBy: user.id
    };

    currentDb.transactions.push(tx);

    // 2. Atualizar Carteira do Destinatário
    let wallet = currentDb.wallets.find((w: any) => w.userId === recipientId);
    if (wallet) {
      wallet.balance += numAmount;
    } else {
      currentDb.wallets.push({ userId: recipientId, balance: numAmount });
    }

    // 3. Registrar Log de Auditoria
    addAuditLog(currentDb, {
      actorUserId: user.id,
      action: 'GIFT_TAMPINHAS',
      entityType: 'TRANSACTION',
      entityId: tx.id,
      details: { to: recipient.name, amount: numAmount, reason }
    });

    // 4. Salvar no LocalStorage e Notificar App
    saveDB(currentDb);
    onRefreshDB();

    alert(`Sucesso! ${numAmount} tampinhas enviadas para ${recipient.name}.`);

    // Resetar formulário
    setAmount('');
    setReason('');
    setRecipientId('');
    setCategory('Reconhecimento');
