import React, { useState } from 'react';
import { User, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('Reconhecimento');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Filtar apenas usuários ativos e que não sejam o próprio líder
  // Importante: Usamos o db vindo por props para renderizar a lista
  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    const numAmount = Number(amount);

    if (numAmount <= 0) {
      alert('Quantidade deve ser maior que zero!');
      return;
    }
    if (!recipientId) {
      alert('Selecione um destinatário!');
      return;
    }
    if (!reason.trim()) {
      alert('A justificativa é obrigatória!');
      return;
    }

    try {
      setIsSubmitting(true);

      // BUSCA ATÔMICA: Pegar a versão mais recente do banco de dados antes de alterar
      const currentDb = getDB(); 

      const recipient = currentDb.users.find((u: User) => u.id === recipientId);
      if (!recipient) {
        alert('Destinatário não encontrado ou inativo no banco de dados.');
        setIsSubmitting(false);
        return;
      }

      if (!confirm(`Confirmar envio de ${numAmount} tampinhas para ${recipient.name}?`)) {
        setIsSubmitting(false);
        return;
      }

      // 1. Registrar a Transação
      const tx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: numAmount,
        fromUserId: user.id,
        toUserId: recipientId,
        reason: reason,
        category: category,
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };

      currentDb.transactions.unshift(tx);

      // 2. Atualizar o Saldo (Wallet)
      // Garantir que a wallet existe, se não, criar
      let walletIndex = currentDb.wallets.findIndex((w: any) => w.userId === recipientId);

      if (walletIndex !== -1) {
        currentDb.wallets[walletIndex].balance = Number(currentDb.wallets[walletIndex].balance) + numAmount;
      } else {
        currentDb.wallets.push({ userId: recipientId, balance: numAmount });
      }

      // 3. Log de Auditoria
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'GIFT_TAMPINHAS',
        entityType: 'TRANSACTION',
        entityId: tx.id,
        details: { to: recipient.name, corporateId: recipient.corporateId, amount: numAmount, category }
      });

      // 4. Salvar Persistente
      saveDB(currentDb);

      // 5. Sincronizar UI Global
      onRefreshDB();

      alert(`Reconhecimento enviado com sucesso para ${recipient.name}!`);

      // Resetar Form
      setAmount('');
      setReason('');
      setRecipientId('');
      setCategory('Reconhecimento');

    } catch (error) {
      console.error("Erro ao enviar tampinhas:", error);
      alert("Ocorreu um erro ao processar o envio. Tente novamente.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-10">
      <header>
        <p className="text-yellow-500 font-black text-[10px] uppercase tracking-[0.3em] mb-1 italic opacity-80">Cultura de Reconhecimento</p>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Dar Tampinhas</h1>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
