export const getDB = (): DB => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DB));
    return INITIAL_DB;
  }
  try {
    const parsed = JSON.parse(data);
    // Garantir que campos novos existam se o DB for de uma versão anterior
    return { ...INITIAL_DB, ...parsed };
  } catch (e) {
    return INITIAL_DB;
  }
};

export const saveDB = (db: DB) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const addAuditLog = (db: DB, log: Omit<AuditLog, 'id' | 'createdAt'>) => {
  const newLog: AuditLog = {
    ...log,
    id: Math.random().toString(36).substr(2, 9),
    createdAt: new Date().toISOString()
  };
  db.auditLogs.unshift(newLog);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, 
  RewardItem, Order, OrderStatus, TransactionType 
} from './types';
import { getDB, saveDB, addAuditLog } from './store';

// Pages
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Store from './pages/Store';
import MyOrders from './pages/MyOrders';
import Leadership from './pages/Leadership';
import Approvals from './pages/Approvals';
import Admin from './pages/Admin';
import Sidebar from './components/Sidebar';
import Topbar from './components/Topbar';

const App: React.FC = () => {
  const [db, setDb] = useState(getDB());
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');

  // Recuperação de Sessão Persistente
  useEffect(() => {
    const savedUserId = localStorage.getItem('current_user_id');
    if (savedUserId) {
      const dbUser = db.users.find(u => u.id === savedUserId);
      if (dbUser && dbUser.status === UserStatus.ACTIVE) {
        setUser(dbUser);
        setView('DASHBOARD');
      } else {
        localStorage.removeItem('current_user_id');
      }
    }
  }, []);

  // Sincronizar dados do usuário se o DB mudar (ex: admin mudou capacidades)
  useEffect(() => {
    if (user) {
      const dbUser = db.users.find(u => u.id === user.id);
      if (dbUser && JSON.stringify(dbUser) !== JSON.stringify(user)) {
        setUser(dbUser);
      }
    }
  }, [db.users]);

  const handleLogin = (u: User) => {
    if (u.status === UserStatus.PENDING) {
      alert('Sua conta ainda está pendente de aprovação pelo Administrador.');
      return;
    }
    if (u.status === UserStatus.BLOCKED) {
      alert('Sua conta está bloqueada. Entre em contato com o suporte.');
      return;
    }
    setUser(u);
    localStorage.setItem('current_user_id', u.id);
    setView('DASHBOARD');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user_id');
    setView('LOGIN');
  };

  const refreshDB = () => {
    const newDb = getDB();
    setDb(newDb);
  };

  const userWallet = useMemo(() => {
    if (!user) return { userId: '', balance: 0 };
    // Busca o saldo atualizado sempre que o DB ou o usuário mudarem
    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0 };
  }, [user, db.wallets]);

  if (view === 'LOGIN') return <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} onRefreshDB={refreshDB} />;
  if (view === 'REGISTER') return <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} />;

  return (
    <div className="flex min-h-screen bg-black">
      <Sidebar 
        currentView={view} 
        setView={setView} 
        capabilities={user?.capabilities || []} 
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Topbar 
          user={user} 
          balance={userWallet.balance} 
          onLogout={handleLogout} 
        />

        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-black">
          <div className="max-w-7xl mx-auto">
            {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
            {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} />}
            {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
            {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} />}
            {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} />}
            {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';

export type ToastType = 'success' | 'error' | 'warning' | 'info';

interface ToastProps {
  message: string;
  type: ToastType;
  onClose: () => void;
}

const Toast: React.FC<ToastProps> = ({ message, type, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 5000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const styles = {
    success: 'bg-emerald-500 border-emerald-400 text-black',
    error: 'bg-rose-500 border-rose-400 text-white',
    warning: 'bg-yellow-500 border-yellow-400 text-black',
    info: 'bg-zinc-800 border-zinc-700 text-white'
  };

  const icons = {
    success: 'fa-circle-check',
    error: 'fa-circle-xmark',
    warning: 'fa-triangle-exclamation',
    info: 'fa-circle-info'
  };

  return (
    <div className={`fixed bottom-8 right-8 z-[100] flex items-center gap-4 px-6 py-4 rounded-2xl border-2 shadow-2xl animate-in slide-in-from-right-10 duration-300 ${styles[type]}`}>
      <i className={`fa-solid ${icons[type]} text-xl`}></i>
      <div className="flex flex-col">
        <p className="font-black uppercase italic text-[10px] tracking-widest opacity-70 leading-none mb-1">Notificação</p>
        <p className="font-bold text-sm tracking-tight">{message}</p>
      </div>
      <button onClick={onClose} className="ml-4 opacity-50 hover:opacity-100 transition-opacity">
        <i className="fa-solid fa-xmark"></i>
      </button>
    </div>
  );
};

