      status: UserStatus.PENDING,
      roles: [Role.USER],
      capabilities: [Capability.RECEIVE_ONLY],
      createdAt: new Date().toISOString()
    };

    db.users.push(newUser);
    db.wallets.push({ userId: newUser.id, balance: 0 });

