import React, { useState } from 'react';
import { User, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('Reconhecimento');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Lista de usuários ativos (exceto o próprio líder)
  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    const numAmount = Number(amount);

    // Validações Básicas
    if (!recipientId) {
      showToast('Por favor, selecione um colaborador para receber as tampinhas.', 'warning');
      return;
    }
    if (numAmount <= 0) {
      showToast('A quantidade de tampinhas deve ser maior que zero.', 'warning');
      return;
    }
    if (!reason.trim() || reason.length < 5) {
      showToast('A justificativa é obrigatória e deve ser detalhada.', 'warning');
      return;
    }

    try {
      setIsSubmitting(true);

      // 1. CARREGAMENTO FRESCO: Busca a versão mais recente do DB diretamente do LocalStorage
      const currentDb = getDB(); 

      // 2. Localiza o destinatário no DB atualizado
      const recipient = currentDb.users.find((u: User) => u.id === recipientId);
      if (!recipient) {
        showToast('Erro: Colaborador não encontrado ou inativo no sistema.', 'error');
        setIsSubmitting(false);
        return;
      }

      // 3. REGISTRA A TRANSAÇÃO
      const tx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: numAmount,
        fromUserId: user.id,
        toUserId: recipientId,
        reason: reason.trim(),
        category: category,
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };

      currentDb.transactions.unshift(tx);

      // 4. ATUALIZA A CARTEIRA (WALLET)
      let walletIndex = currentDb.wallets.findIndex((w: any) => w.userId === recipientId);

      if (walletIndex !== -1) {
        // Garante que o cálculo seja numérico para evitar concatenação de strings
        currentDb.wallets[walletIndex].balance = Number(currentDb.wallets[walletIndex].balance) + numAmount;
      } else {
        // Caso não exista carteira (fallback de segurança)
        currentDb.wallets.push({ userId: recipientId, balance: numAmount });
      }

      // 5. REGISTRA NA AUDITORIA
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'GIFT_TAMPINHAS',
        entityType: 'TRANSACTION',
        entityId: tx.id,
        details: { 
          para: recipient.name, 
          id_corporativo: recipient.corporateId, 
          valor: numAmount, 
          categoria: category 
        }
      });

      // 6. PERSISTÊNCIA FÍSICA
      saveDB(currentDb);

      // 7. ATUALIZAÇÃO DA INTERFACE
      onRefreshDB();

      showToast(`Sucesso! ${numAmount} tampinhas enviadas para ${recipient.name}.`, 'success');

      // Limpa o formulário após o sucesso
      setAmount('');
      setReason('');
      setRecipientId('');
      setCategory('Reconhecimento');

    } catch (error) {
      console.error("Falha na transação:", error);
      showToast('Erro técnico ao processar o envio. Verifique sua conexão.', 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-10">
      <header>
        <p className="text-yellow-500 font-black text-[10px] uppercase tracking-[0.3em] mb-1 italic opacity-80">Reconhecimento Digital</p>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Enviar Tampinhas</h1>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
        <div className="lg:col-span-3">
          <form onSubmit={handleSubmit} className="bg-zinc-900/40 p-8 rounded-[2.5rem] border border-zinc-800 space-y-6 shadow-2xl relative overflow-hidden">
            {isSubmitting && (
              <div className="absolute inset-0 bg-black/60 backdrop-blur-sm z-20 flex items-center justify-center">
                <i className="fa-solid fa-circle-notch fa-spin text-4xl text-yellow-500"></i>
              </div>
            )}

            <div className="space-y-2">
              <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Para quem é o reconhecimento?</label>
              <div className="relative">
                <select 
                  required
                  className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl appearance-none focus:border-yellow-500 outline-none font-bold transition-all"
                  value={recipientId}
                  onChange={e => setRecipientId(e.target.value)}
                >
                  <option value="">Selecione um colaborador...</option>
                  {activeUsers.map((u: User) => (
                    <option key={u.id} value={u.id}>{u.name.toUpperCase()} (ID: {u.corporateId})</option>
                  ))}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                  <i className="fa-solid fa-chevron-down"></i>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Quantidade de Tampinhas</label>
                <input 
                  type="number" required min="1"
                  className="w-full p-4 bg-black border border-zinc-800 text-yellow-500 font-black rounded-2xl focus:border-yellow-500 outline-none text-2xl transition-all"
                  placeholder="0"
                  value={amount}
                  onChange={e => setAmount(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Motivo Principal</label>
                <div className="relative">
                  <select 
                    className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl appearance-none focus:border-yellow-500 outline-none font-bold transition-all"
                    value={category}
                    onChange={e => setCategory(e.target.value)}
                  >
                    <option>Reconhecimento</option>
                    <option>Meta Batida</option>
                    <option>Destaque do Mês</option>
                    <option>Cultura Supply</option>
                    <option>Segurança em Primeiro Lugar</option>
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                    <i className="fa-solid fa-chevron-down"></i>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Justificativa do Reconhecimento</label>
              <textarea 
                required rows={4}
                className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-medium transition-all"
                placeholder="Conte para nós e para o colaborador o porquê deste reconhecimento..."
                value={reason}
                onChange={e => setReason(e.target.value)}
              ></textarea>
            </div>

            <button 
              type="submit"
              disabled={isSubmitting}
              className={`w-full py-5 rounded-2xl font-black text-lg uppercase tracking-widest transition-all shadow-lg flex items-center justify-center gap-3 active:scale-[0.98] ${
                isSubmitting ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400 shadow-yellow-500/10'
              }`}
            >
              <i className={`fa-solid ${isSubmitting ? 'fa-spinner fa-spin' : 'fa-paper-plane'}`}></i>
              {isSubmitting ? 'Enviando...' : 'Confirmar Envio'}
            </button>
          </form>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="bg-yellow-500 p-8 rounded-[2.5rem] text-black relative overflow-hidden shadow-xl group">
             <i className="fa-solid fa-bolt absolute -right-4 -bottom-4 text-9xl opacity-10 group-hover:scale-110 transition-transform"></i>
             <h4 className="font-black text-xl uppercase italic mb-2 tracking-tighter">Impacto em Tempo Real</h4>
             <p className="text-sm font-bold leading-tight opacity-80 uppercase italic">
               Ao confirmar, o colaborador receberá uma notificação e o saldo estará disponível instantaneamente.
             </p>
          </div>

          <div className="bg-zinc-900/20 p-8 rounded-[2.5rem] border border-zinc-800 shadow-xl">
            <h4 className="font-black text-white uppercase tracking-widest text-[10px] mb-6 italic opacity-50 underline decoration-yellow-500 underline-offset-4">Regras de Ouro</h4>
            <ul className="space-y-6">
              <li className="flex gap-4">
                <i className="fa-solid fa-circle-check text-yellow-500 mt-1"></i>
                <p className="text-[11px] text-zinc-400 font-bold uppercase leading-snug">Seja específico na justificativa para valorizar o esforço.</p>
              </li>
              <li className="flex gap-4">
                <i className="fa-solid fa-circle-check text-yellow-500 mt-1"></i>
                <p className="text-[11px] text-zinc-400 font-bold uppercase leading-snug">O envio de tampinhas é definitivo e auditado pelo sistema.</p>
              </li>
              <li className="flex gap-4">
                <i className="fa-solid fa-circle-check text-yellow-500 mt-1"></i>
                <p className="text-[11px] text-zinc-400 font-bold uppercase leading-snug">Líderes devem promover a cultura de segurança e eficiência.</p>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

