import React, { useState } from 'react';
import { User, RewardItem, OrderStatus, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface StoreProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Store: React.FC<StoreProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [filter, setFilter] = useState('');
  const [category, setCategory] = useState('Todas');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  const categories = ['Todas', ...Array.from(new Set(db.rewardItems.map((i: any) => i.category)))];
  const wallet = db.wallets.find((w: any) => w.userId === user.id) || { balance: 0 };

  const filteredItems = db.rewardItems.filter((item: RewardItem) => {
    const matchesSearch = item.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCategory = category === 'Todas' || item.category === category;
    return matchesSearch && matchesCategory && item.isActive;
  });

  const handlePurchase = async (item: RewardItem) => {
    if (wallet.balance < item.cost) {
      showToast('Você não possui tampinhas suficientes para este item.', 'warning');
      return;
    }
    if (item.stock <= 0) {
      showToast('Este item está temporariamente sem estoque.', 'error');
      return;
    }

    if (!confirm(`Confirmar resgate de "${item.name}" por ${item.cost} tampinhas?`)) return;

    try {
      setIsProcessing(item.id);

      // Busca DB atualizado
      const currentDb = getDB();

      // Cria o Pedido
      const newOrder = {
        id: Math.random().toString(36).substr(2, 9),
        userId: user.id,
        status: OrderStatus.PENDING,
        totalCost: item.cost,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        items: [{ itemId: item.id, qty: 1, costEach: item.cost }]
      };

      currentDb.orders.unshift(newOrder);

      // Auditoria
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'ORDER_REQUEST',
        entityType: 'ORDER',
        entityId: newOrder.id,
        details: { item: item.name, cost: item.cost }
      });

      saveDB(currentDb);
      onRefreshDB();

      showToast('Solicitação enviada com sucesso! Aguarde a aprovação.', 'success');

    } catch (e) {
      showToast('Erro ao processar resgate. Tente novamente.', 'error');
    } finally {
      setIsProcessing(null);
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 rounded-[1.5rem] bg-yellow-500 flex items-center justify-center shadow-lg shadow-yellow-500/20">
            <i className="fa-solid fa-gift text-black text-3xl"></i>
          </div>
          <div>
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Loja de Brindes</h1>
            <p className="text-zinc-500 font-bold uppercase text-[10px] tracking-widest mt-1 italic">Transforme seu esforço em recompensas.</p>
          </div>
        </div>

        <div className="bg-zinc-900/50 backdrop-blur-md border border-zinc-800 p-6 rounded-[2.5rem] flex items-center gap-6 shadow-xl">
           <div className="w-12 h-12 rounded-full border-2 border-yellow-500/30 flex items-center justify-center bg-black">
             <i className="fa-solid fa-wallet text-yellow-500"></i>
           </div>
           <div>
             <p className="text-[10px] uppercase font-black text-zinc-500 tracking-widest leading-none mb-1">Seu Saldo Disponível</p>
             <p className="text-3xl font-black text-white italic tracking-tighter">{wallet.balance} <span className="text-xs text-yellow-500 uppercase not-italic">Tampinhas</span></p>
           </div>
        </div>
      </header>

      {/* Filtros */}
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-zinc-900/40 p-4 rounded-3xl border border-zinc-800 shadow-lg">
        <div className="relative w-full md:w-96">
          <i className="fa-solid fa-magnifying-glass absolute left-5 top-4 text-zinc-600"></i>
          <input 
            type="text" 
            placeholder="O que você está procurando?"
            className="w-full pl-14 pr-6 py-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold placeholder:text-zinc-700"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
          {categories.map(cat => (
            <button
              key={cat as string}
              onClick={() => setCategory(cat as string)}
              className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all border ${
                category === cat 
                ? 'bg-yellow-500 text-black border-yellow-500 shadow-lg shadow-yellow-500/10' 
                : 'bg-black text-zinc-500 border-zinc-800 hover:border-zinc-600'
              }`}
            >
              {cat as string}
