            <div className="relative h-56 bg-zinc-800 overflow-hidden">
              <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-80 group-hover:opacity-100" />
              <div className="absolute top-5 left-5">
                <span className="px-4 py-1.5 bg-black/80 backdrop-blur-md rounded-full text-[9px] font-black text-yellow-500 border border-yellow-500/20 uppercase tracking-widest">
                  {item.category}
