              </div>

              <button 
                disabled={item.stock <= 0 || wallet.balance < item.cost || !!isProcessing}
                onClick={() => handlePurchase(item)}
                className={`mt-8 w-full py-4 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 active:scale-95 shadow-lg ${
                  item.stock <= 0 || wallet.balance < item.cost
                  ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-50'
                  : 'bg-yellow-500 text-black hover:bg-yellow-400 shadow-yellow-500/10'
                }`}
              >
                {isProcessing === item.id ? (
                  <i className="fa-solid fa-circle-notch fa-spin"></i>
                ) : (
                  <i className="fa-solid fa-cart-shopping"></i>
                )}
                {wallet.balance < item.cost ? 'Saldo Insuficiente' : isProcessing === item.id ? 'Processando...' : 'Resgatar Agora'}
              </button>
            </div>
          </div>
        ))}

        {filteredItems.length === 0 && (
          <div className="col-span-full py-20 text-center space-y-4">
             <i className="fa-solid fa-face-frown text-6xl text-zinc-800"></i>
             <p className="text-zinc-500 font-black uppercase tracking-widest text-sm italic">Nenhum brinde encontrado para sua busca.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Store;

import React, { useState } from 'react';
import { User, Order, OrderStatus, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface ApprovalsProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Approvals: React.FC<ApprovalsProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<OrderStatus>(OrderStatus.PENDING);
  const [note, setNote] = useState('');
  const [processingId, setProcessingId] = useState<string | null>(null);

  const filteredOrders = db.orders.filter((o: Order) => {
    if (activeTab === OrderStatus.PENDING) return o.status === OrderStatus.PENDING;
    return o.status !== OrderStatus.PENDING;
  }).sort((a: any, b: any) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const processDecision = async (orderId: string, decision: OrderStatus) => {
    if (decision !== OrderStatus.APPROVED && !note.trim()) {
      showToast('É obrigatório adicionar uma justificativa para reprovar ou pedir ajuste.', 'warning');
      return;
    }

    try {
      setProcessingId(orderId);

      // Carrega DB fresco
      const currentDb = getDB();
      const order = currentDb.orders.find(o => o.id === orderId);

      if (!order) {
        showToast('Erro: Pedido não encontrado no banco de dados.', 'error');
        return;
      }

      const requester = currentDb.users.find((u: User) => u.id === order.userId);
      const requesterWallet = currentDb.wallets.find((w: any) => w.userId === order.userId);

      if (decision === OrderStatus.APPROVED) {
        // Valida saldo no momento da aprovação
        if (!requesterWallet || requesterWallet.balance < order.totalCost) {
          showToast(`Erro: ${requester?.name} não possui mais saldo suficiente.`, 'error');
          return;
        }

        // Valida estoque no momento da aprovação
        for (const oi of order.items) {
          const item = currentDb.rewardItems.find((ri: any) => ri.id === oi.itemId);
          if (!item || item.stock < oi.qty) {
            showToast(`Erro: Estoque insuficiente para o item ${item?.name || 'desconhecido'}.`, 'error');
            return;
          }
        }

        // TRANSAÇÃO ATÔMICA
        requesterWallet.balance -= order.totalCost;

        const debitTx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          type: TransactionType.DEBIT,
          amount: order.totalCost,
          fromUserId: requester.id,
          toUserId: 'REWARD_STORE',
          reason: `Resgate Aprovado (Pedido #${order.id})`,
          category: 'Resgate',
          createdAt: new Date().toISOString(),
          createdBy: user.id
        };
        currentDb.transactions.unshift(debitTx);

        for (const oi of order.items) {
          const item = currentDb.rewardItems.find((ri: any) => ri.id === oi.itemId);
          if (item) item.stock -= oi.qty;
        }
      }

      // Atualiza Pedido
      const orderToUpdate = currentDb.orders.find(o => o.id === orderId);
      if (orderToUpdate) {
        orderToUpdate.status = decision;
        orderToUpdate.note = note.trim();
        orderToUpdate.approverId = user.id;
        orderToUpdate.updatedAt = new Date().toISOString();
      }

      // Auditoria
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: `ORDER_${decision}`,
        entityType: 'ORDER',
        entityId: orderId,
        details: { justificativa: note, usuario: requester?.name }
      });

      saveDB(currentDb);
      onRefreshDB();
      setNote('');
      showToast(`Ação "${decision}" realizada com sucesso!`, 'success');

    } catch (e) {
      showToast('Erro ao processar a decisão.', 'error');
    } finally {
      setProcessingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <header>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Fila de Aprovações</h1>
        <p className="text-zinc-500 font-bold uppercase text-[10px] tracking-widest mt-1 italic">Analise solicitações de resgate da equipe.</p>
      </header>

      <div className="flex gap-2 bg-zinc-900/50 p-2 rounded-2xl w-fit border border-zinc-800">
        <button 
          onClick={() => setActiveTab(OrderStatus.PENDING)}
          className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === OrderStatus.PENDING ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-zinc-500 hover:text-white'}`}
        >
          Pendentes
        </button>
        <button 
          onClick={() => setActiveTab(OrderStatus.APPROVED)}
          className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab !== OrderStatus.PENDING ? 'bg-white text-black shadow-lg shadow-white/10' : 'text-zinc-500 hover:text-white'}`}
        >
          Histórico Total
        </button>
      </div>

      <div className="grid gap-6">
        {filteredOrders.length === 0 ? (
          <div className="bg-zinc-900/20 p-20 rounded-[3rem] border border-dashed border-zinc-800 text-center flex flex-col items-center">
             <i className="fa-solid fa-stamp text-5xl text-zinc-800 mb-4"></i>
             <p className="text-zinc-600 font-black uppercase text-xs tracking-widest italic">Nenhuma solicitação aguardando sua decisão.</p>
          </div>
        ) : (
          filteredOrders.map((order: Order) => {
            const requester = db.users.find((u: any) => u.id === order.userId);
            const wallet = db.wallets.find((w: any) => w.userId === order.userId) || { balance: 0 };
            const isProcessing = processingId === order.id;

            return (
              <div key={order.id} className="bg-zinc-900/40 p-8 rounded-[2.5rem] border border-zinc-800 flex flex-col lg:flex-row gap-10 shadow-2xl relative overflow-hidden group">
                <div className="flex-1 space-y-8">
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="flex items-center gap-3 mb-2">
                        <span className="text-[10px] font-black text-yellow-500 uppercase tracking-widest px-3 py-1 bg-yellow-500/10 rounded-lg border border-yellow-500/20">Solicitação #{order.id}</span>
                      </div>
                      <h4 className="text-2xl font-black text-white italic uppercase tracking-tighter">{requester?.name}</h4>
                      <div className="flex gap-4 mt-2">
                         <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">ID: {requester?.corporateId}</p>
                         <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Data: {new Date(order.createdAt).toLocaleString()}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-[10px] uppercase font-black text-zinc-600 tracking-widest mb-1">Custo do Pedido</p>
                      <p className="text-3xl font-black text-yellow-500 italic tracking-tighter leading-none">{order.totalCost} t.</p>
                      <p className="text-[9px] text-zinc-500 font-black uppercase tracking-widest mt-2">Saldo do Colab: {wallet.balance} t.</p>
                    </div>
                  </div>

                  <div className="bg-black/40 p-6 rounded-3xl border border-zinc-800">
                    <p className="text-[9px] font-black text-zinc-600 uppercase mb-4 tracking-[0.2em] italic">Itens da Solicitação</p>
                    <div className="space-y-4">
                      {order.items.map((oi, idx) => {
                        const item = db.rewardItems.find((ri: any) => ri.id === oi.itemId);
                        return (
                          <div key={idx} className="flex items-center justify-between group/item">
                            <div className="flex items-center gap-4">
                              <img src={item?.imageUrl} className="w-10 h-10 rounded-xl object-cover grayscale group-hover/item:grayscale-0 transition-all" />
                              <span className="text-xs font-black text-white uppercase italic tracking-tight">{item?.name} <span className="text-zinc-600 not-italic ml-2">x{oi.qty}</span></span>
                            </div>
                            <span className="text-xs font-black text-zinc-500 italic tracking-tighter">{oi.costEach * oi.qty} t.</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="w-full lg:w-96 flex flex-col justify-between">
                  {order.status === OrderStatus.PENDING ? (
                    <div className="space-y-4 bg-black/30 p-6 rounded-3xl border border-zinc-800 h-full flex flex-col">
                      <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Observações Internas</label>
                      <textarea 
                        className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl text-xs focus:border-yellow-500 outline-none flex-1 font-medium"
                        placeholder="Justificativa para o colaborador saber o motivo da sua decisão..."
                        rows={3}
                        value={note}
                        onChange={e => setNote(e.target.value)}
                      ></textarea>

                      <div className="grid grid-cols-2 gap-3 mt-4">
                        <button 
                          disabled={isProcessing}
                          onClick={() => processDecision(order.id, OrderStatus.REJECTED)}
                          className="py-4 bg-zinc-900 border border-zinc-800 text-zinc-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:border-rose-500/50 hover:text-rose-500 transition-all active:scale-95"
                        >
                          Reprovar
                        </button>
                        <button 
                          disabled={isProcessing}
                          onClick={() => processDecision(order.id, OrderStatus.ADJUSTMENT_REQUESTED)}
                          className="py-4 bg-zinc-900 border border-zinc-800 text-zinc-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:border-blue-500/50 hover:text-blue-500 transition-all active:scale-95"
                        >
                          Pedir Ajuste
                        </button>
                      </div>

                      <button 
                        disabled={isProcessing}
                        onClick={() => processDecision(order.id, OrderStatus.APPROVED)}
                        className="w-full py-5 bg-yellow-500 text-black rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-yellow-400 shadow-lg shadow-yellow-500/10 transition-all flex items-center justify-center gap-3 active:scale-95 mt-3"
                      >
                        {isProcessing ? (
                          <i className="fa-solid fa-circle-notch fa-spin"></i>
                        ) : (
                          <i className="fa-solid fa-stamp"></i>
                        )}
                        {isProcessing ? 'Processando...' : 'Aprovar Resgate'}
                      </button>
                    </div>
                  ) : (
                    <div className="h-full flex flex-col justify-center items-center p-8 bg-black/40 rounded-[2rem] border border-zinc-800 border-dashed text-center">
                        <p className="text-[9px] uppercase font-black text-zinc-600 tracking-widest mb-3 italic">Decisão do Aprovador</p>
                        <p className={`text-2xl font-black uppercase italic tracking-tighter mb-1 ${
                          order.status === OrderStatus.APPROVED ? 'text-emerald-500' : 
                          order.status === OrderStatus.REJECTED ? 'text-rose-500' : 'text-blue-500'
                        }`}>{order.status}</p>
                        <p className="text-[9px] text-zinc-500 font-bold uppercase tracking-widest">Em {new Date(order.updatedAt).toLocaleDateString()}</p>
                        {order.note && (
                          <div className="mt-6 w-full p-4 bg-zinc-900/50 rounded-2xl border border-zinc-800 relative">
                             <i className="fa-solid fa-quote-left absolute -top-2 -left-1 text-yellow-500/20 text-xl"></i>
                             <p className="text-[10px] italic text-zinc-400 font-medium leading-relaxed">"{order.note}"</p>
                          </div>
                        )}
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default Approvals;

import React, { useState, useMemo } from 'react';
import { User, RewardItem, OrderStatus, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface StoreProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

interface CartItem extends RewardItem {
  quantity: number;
}

const Store: React.FC<StoreProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [filter, setFilter] = useState('');
  const [category, setCategory] = useState('Todas');
  const [isProcessing, setIsProcessing] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);

  const categories = ['Todas', ...Array.from(new Set(db.rewardItems.map((i: any) => i.category)))];
  const wallet = db.wallets.find((w: any) => w.userId === user.id) || { balance: 0 };

  const filteredItems = db.rewardItems.filter((item: RewardItem) => {
    const matchesSearch = item.name.toLowerCase().includes(filter.toLowerCase());
    const matchesCategory = category === 'Todas' || item.category === category;
    return matchesSearch && matchesCategory && item.isActive;
  });

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => acc + (item.cost * item.quantity), 0);
  }, [cart]);

  const addToCart = (item: RewardItem) => {
    if (item.stock <= 0) {
      showToast('Este item está sem estoque.', 'error');
      return;
    }

    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        if (existing.quantity >= item.stock) {
          showToast('Quantidade máxima em estoque atingida.', 'warning');
          return prev;
        }
        showToast(`${item.name} adicionado ao carrinho!`, 'success');
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      showToast(`${item.name} adicionado ao carrinho!`, 'success');
      return [...prev, { ...item, quantity: 1 }];
    });
    setShowCart(true);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(i => i.id !== itemId));
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;

    if (wallet.balance < cartTotal) {
      showToast('Seu saldo de tampinhas é insuficiente para este pedido.', 'error');
      return;
    }

    try {
      setIsProcessing(true);
      const currentDb = getDB();

      const newOrder = {
        id: Math.random().toString(36).substr(2, 9).toUpperCase(),
        userId: user.id,
        status: OrderStatus.PENDING,
        totalCost: cartTotal,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        items: cart.map(item => ({
          itemId: item.id,
          qty: item.quantity,
          costEach: item.cost
        }))
      };

      currentDb.orders.unshift(newOrder);

      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'ORDER_REQUEST_MULTIPLE',
        entityType: 'ORDER',
        entityId: newOrder.id,
        details: { itemsCount: cart.length, total: cartTotal }
      });

      saveDB(currentDb);
      onRefreshDB();

      setCart([]);
      setShowCart(false);
      showToast('Pedido realizado! Aguarde a aprovação do líder.', 'success');

    } catch (e) {
      showToast('Erro ao processar o pedido. Tente novamente.', 'error');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="relative min-h-screen">
      <div className={`space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20 ${showCart ? 'lg:mr-96' : ''} transition-all`}>
        <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-[1.5rem] bg-yellow-500 flex items-center justify-center shadow-lg shadow-yellow-500/20">
              <i className="fa-solid fa-gift text-black text-3xl"></i>
            </div>
            <div>
              <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Loja de Brindes</h1>
              <p className="text-zinc-500 font-bold uppercase text-[10px] tracking-widest mt-1 italic">Troque suas tampinhas por prêmios incríveis.</p>
            </div>
          </div>

          <div className="flex gap-4">
            <button 
              onClick={() => setShowCart(!showCart)}
              className="relative bg-zinc-900 border border-zinc-800 p-4 rounded-2xl text-white hover:border-yellow-500 transition-all"
            >
              <i className="fa-solid fa-cart-shopping text-xl"></i>
              {cart.length > 0 && (
                <span className="absolute -top-2 -right-2 w-6 h-6 bg-yellow-500 text-black text-[10px] font-black rounded-full flex items-center justify-center border-2 border-black animate-bounce">
                  {cart.length}
                </span>
              )}
            </button>
            <div className="bg-zinc-900/50 backdrop-blur-md border border-zinc-800 px-6 py-3 rounded-2xl flex items-center gap-4 shadow-xl">
               <p className="text-3xl font-black text-white italic tracking-tighter leading-none">{wallet.balance} <span className="text-[10px] text-yellow-500 uppercase not-italic block tracking-widest">Saldo</span></p>
            </div>
          </div>
        </header>

        {/* Filtros */}
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-zinc-900/40 p-4 rounded-3xl border border-zinc-800 shadow-lg">
          <div className="relative w-full md:w-96">
            <i className="fa-solid fa-magnifying-glass absolute left-5 top-4 text-zinc-600"></i>
            <input 
              type="text" 
              placeholder="Pesquisar brinde..."
              className="w-full pl-14 pr-6 py-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold placeholder:text-zinc-700"
              value={filter}
              onChange={e => setFilter(e.target.value)}
            />
          </div>
          <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
            {categories.map(cat => (
              <button
                key={cat as string}
                onClick={() => setCategory(cat as string)}
                className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all border ${
                  category === cat 
                  ? 'bg-yellow-500 text-black border-yellow-500 shadow-lg shadow-yellow-500/10' 
                  : 'bg-black text-zinc-500 border-zinc-800 hover:border-zinc-600'
                }`}
              >
                {cat as string}
              </button>
            ))}
          </div>
        </div>

        {/* Grid de Itens */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredItems.map((item: RewardItem) => (
            <div key={item.id} className="bg-zinc-900/40 rounded-[2.5rem] overflow-hidden border border-zinc-800 flex flex-col group hover:border-yellow-500/50 transition-all shadow-2xl relative">
              <div className="relative h-48 bg-zinc-800 overflow-hidden">
                <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-80" />
                <div className="absolute top-4 left-4">
                  <span className="px-3 py-1 bg-black/80 backdrop-blur-md rounded-full text-[8px] font-black text-yellow-500 border border-yellow-500/20 uppercase">
                    {item.category}
                  </span>
                </div>
              </div>

              <div className="p-6 flex-1 flex flex-col">
                <h3 className="text-lg font-black text-white italic uppercase tracking-tighter mb-1 leading-tight">{item.name}</h3>
                <p className="text-zinc-500 text-[10px] font-medium mb-4 flex-1 line-clamp-2">{item.description}</p>

                <div className="flex items-center justify-between mb-6">
                  <div className="flex flex-col">
                    <span className="text-[8px] font-black text-zinc-600 uppercase tracking-widest">Custo</span>
                    <div className="flex items-center gap-1">
                      <span className="text-2xl font-black text-white italic tracking-tighter leading-none">{item.cost}</span>
                      <i className="fa-solid fa-bottle-cap text-yellow-500 text-[10px]"></i>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] uppercase font-black text-zinc-600 tracking-widest">Estoque</p>
                    <p className={`text-xs font-black italic ${item.stock < 3 ? 'text-rose-500' : 'text-emerald-500'}`}>{item.stock} un</p>
                  </div>
                </div>

                <button 
                  disabled={item.stock <= 0}
                  onClick={() => addToCart(item)}
                  className={`w-full py-4 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 active:scale-95 shadow-lg ${
                    item.stock <= 0
                    ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed'
                    : 'bg-yellow-500 text-black hover:bg-yellow-400'
                  }`}
                >
                  <i className="fa-solid fa-plus"></i>
                  Adicionar
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Painel do Carrinho Sidebar */}
      <div className={`fixed top-0 right-0 h-screen w-full lg:w-96 bg-zinc-900 border-l border-zinc-800 z-50 transform transition-transform duration-500 ease-out shadow-2xl flex flex-col ${showCart ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-8 flex items-center justify-between border-b border-zinc-800 bg-black/20">
          <div>
            <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter leading-none">Seu Carrinho</h2>
            <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-1">Confira seus itens antes de resgatar.</p>
          </div>
          <button onClick={() => setShowCart(false)} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-400 hover:text-white flex items-center justify-center transition-colors">
            <i className="fa-solid fa-xmark"></i>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center opacity-30">
              <i className="fa-solid fa-cart-arrow-down text-6xl mb-4"></i>
              <p className="text-xs font-black uppercase tracking-widest">Carrinho Vazio</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="bg-black/40 p-4 rounded-2xl border border-zinc-800 flex gap-4 animate-in slide-in-from-right-4 duration-300">
                <img src={item.imageUrl} className="w-16 h-16 rounded-xl object-cover grayscale" />
                <div className="flex-1 min-w-0">
                  <h4 className="text-xs font-black text-white uppercase italic truncate mb-1">{item.name}</h4>
                  <p className="text-[10px] text-yellow-500 font-black italic">{item.cost} t. <span className="text-zinc-500 font-medium not-italic ml-2">x{item.quantity}</span></p>
                  <div className="flex items-center gap-2 mt-2">
                    <button 
                      onClick={() => removeFromCart(item.id)}
                      className="text-[9px] font-black text-rose-500 uppercase hover:underline"
                    >
                      Remover
                    </button>
                  </div>
                </div>
                <div className="text-right flex flex-col justify-center">
                  <p className="text-sm font-black text-white italic">{item.cost * item.quantity} t.</p>
                </div>
              </div>
            ))
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-8 bg-black/40 border-t border-zinc-800 space-y-6">
            <div className="space-y-2">
              <div className="flex justify-between items-center text-zinc-500">
                <span className="text-[10px] font-black uppercase tracking-widest">Seu Saldo Atual</span>
                <span className="text-xs font-bold">{wallet.balance} tampinhas</span>
              </div>
              <div className="flex justify-between items-end">
                <span className="text-sm font-black text-white uppercase italic tracking-tighter">Total do Pedido</span>
                <div className="text-right">
                  <span className={`text-3xl font-black italic tracking-tighter ${wallet.balance < cartTotal ? 'text-rose-500' : 'text-yellow-500'}`}>
                    {cartTotal} t.
                  </span>
                </div>
              </div>
            </div>

            <button 
              disabled={isProcessing || wallet.balance < cartTotal}
              onClick={handleCheckout}
              className={`w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3 active:scale-95 ${
                wallet.balance < cartTotal || isProcessing
                ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed'
                : 'bg-yellow-500 text-black hover:bg-yellow-400'
              }`}
            >
              {isProcessing ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-check"></i>}
              {wallet.balance < cartTotal ? 'Saldo Insuficiente' : 'Finalizar Resgate'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

