interface DB {
  users: User[];
  wallets: Wallet[];
  transactions: Transaction[];
  rewardItems: RewardItem[];
  orders: Order[];
  auditLogs: AuditLog[];
  config: {
    currencyName: string;
    conversionRate: number;
    donationLimit: number;
  };
}

const INITIAL_DB: DB = {
  users: [
    {
      id: 'admin-uuid',
