    { id: '4', name: 'Garrafa Térmica', description: 'Garrafa 500ml inox', imageUrl: 'https://images.unsplash.com/photo-1602143399364-793175df9576?auto=format&fit=crop&q=80&w=400', cost: 15, stock: 6, category: 'Acessórios', isActive: true }
  ],
  orders: [],
  auditLogs: [],
  config: {
    currencyName: 'tampinhas',
    conversionRate: 1,
    donationLimit: 500
  }
};

export const getDB = (): DB => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DB));
    return INITIAL_DB;
  }
  try {
    const parsed = JSON.parse(data);
    // Migração de dados para wallets se necessário
    const upgradedWallets = parsed.wallets.map((w: any) => ({
      ...w,
      goldCoins: w.goldCoins || 0,
      silverCoins: w.silverCoins || 0,
      bronzeCoins: w.bronzeCoins || 0
    }));
    return { ...INITIAL_DB, ...parsed, wallets: upgradedWallets };
  } catch (e) {
    return INITIAL_DB;
  }
};

export const saveDB = (db: DB) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const addAuditLog = (db: DB, log: Omit<AuditLog, 'id' | 'createdAt'>) => {
  const newLog: AuditLog = {
    ...log,
    id: Math.random().toString(36).substr(2, 9),
    createdAt: new Date().toISOString()
  };
  db.auditLogs.unshift(newLog);
};

