import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, 
  RewardItem, Order, OrderStatus, TransactionType 
} from './types';
import { getDB, saveDB, addAuditLog } from './store';

// Pages
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Store from './pages/Store';
import MyOrders from './pages/MyOrders';
import Leadership from './pages/Leadership';
import Approvals from './pages/Approvals';
import Admin from './pages/Admin';
import Sidebar from './components/Sidebar';
import Topbar from './components/Topbar';
import Toast, { ToastType } from './components/Toast';

const App: React.FC = () => {
  const [db, setDb] = useState(getDB());
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');

  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    setToast({ message, type });
  }, []);

  useEffect(() => {
    const savedUserId = localStorage.getItem('current_user_id');
    if (savedUserId) {
      const dbUser = db.users.find(u => u.id === savedUserId);
      if (dbUser && dbUser.status === UserStatus.ACTIVE) {
        setUser(dbUser);
        setView('DASHBOARD');
      } else if (dbUser && dbUser.status === UserStatus.PENDING) {
        showToast('Sua conta ainda aguarda aprovação.', 'warning');
        localStorage.removeItem('current_user_id');
      } else {
        localStorage.removeItem('current_user_id');
      }
    }
  }, [db.users, showToast]);

  const handleLogin = (u: User) => {
    if (u.status === UserStatus.PENDING) {
      showToast('Acesso negado: cadastro pendente de aprovação pelo Admin.', 'warning');
      return;
    }
    if (u.status === UserStatus.BLOCKED) {
      showToast('Conta bloqueada. Entre em contato com o suporte.', 'error');
      return;
    }
    setUser(u);
    localStorage.setItem('current_user_id', u.id);
    setView('DASHBOARD');
    showToast(`Bem-vindo, ${u.name.split(' ')[0]}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user_id');
    setView('LOGIN');
    showToast('Sessão encerrada.', 'info');
  };

  const refreshDB = () => {
    const newDb = getDB();
    setDb(newDb);
  };

  const userWallet = useMemo(() => {
    if (!user) return { userId: '', balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 };
    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 };
  }, [user, db.wallets]);

  if (view === 'LOGIN') return (
    <>
      <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  if (view === 'REGISTER') return (
    <>
      <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  return (
    <div className="flex min-h-screen bg-black">
      <Sidebar 
        currentView={view} 
        setView={setView} 
        capabilities={user?.capabilities || []} 
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Topbar 
          user={user} 
          wallet={userWallet} 
          onLogout={handleLogout} 
        />

        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-black">
          <div className="max-w-7xl mx-auto">
            {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
            {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
            {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
          </div>
        </main>
      </div>

      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

export default App;

