import React, { useState, useMemo } from 'react';
import { User, TransactionType, Transaction, Capability, CoinType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<string>('1');
  const [reason, setReason] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Determinar qual moeda o usuário doa baseado na capacidade
  const coinConfig = useMemo(() => {
    if (user.capabilities.includes(Capability.ADMIN) || user.capabilities.includes(Capability.GERENTE_FABRIL)) {
      return { type: CoinType.GOLD, weight: 3, label: 'Moeda de Ouro', color: 'text-yellow-500' };
    }
    if (user.capabilities.includes(Capability.GERENTE_AREA)) {
      return { type: CoinType.SILVER, weight: 2, label: 'Moeda de Prata', color: 'text-zinc-400' };
    }
    // Supervisor, Coordenador, Área de Gente e Liderança padrão doam Bronze
    return { type: CoinType.BRONZE, weight: 1, label: 'Moeda de Bronze', color: 'text-orange-600' };
  }, [user.capabilities]);

  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    const numCoins = Number(amount);
    const totalPoints = numCoins * coinConfig.weight;

    if (!recipientId) {
      showToast('Selecione o destinatário.', 'warning');
      return;
    }
    if (numCoins <= 0) {
      showToast('A quantidade deve ser maior que zero.', 'warning');
      return;
    }
    if (!reason.trim()) {
      showToast('A justificativa é obrigatória.', 'warning');
      return;
    }

    try {
      setIsSubmitting(true);
      const currentDb = getDB(); 

      const recipient = currentDb.users.find((u: User) => u.id === recipientId);
      if (!recipient) {
        showToast('Colaborador não encontrado.', 'error');
        setIsSubmitting(false);
        return;
      }

      const tx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPoints,
        coinType: coinConfig.type,
        fromUserId: user.id,
        toUserId: recipientId,
        reason: reason.trim(),
        category: `Reconhecimento (${coinConfig.label})`,
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };

      currentDb.transactions.unshift(tx);

      let walletIndex = currentDb.wallets.findIndex((w: any) => w.userId === recipientId);
      if (walletIndex === -1) {
        currentDb.wallets.push({ userId: recipientId, balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 });
        walletIndex = currentDb.wallets.length - 1;
      }

      // Atualizar contagem específica de moedas e o saldo total
      const wallet = currentDb.wallets[walletIndex];
      wallet.balance += totalPoints;
      if (coinConfig.type === CoinType.GOLD) wallet.goldCoins += numCoins;
      if (coinConfig.type === CoinType.SILVER) wallet.silverCoins += numCoins;
      if (coinConfig.type === CoinType.BRONZE) wallet.bronzeCoins += numCoins;

      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'GIFT_COINS',
        entityType: 'TRANSACTION',
        entityId: tx.id,
        details: { para: recipient.name, valor_pts: totalPoints, moeda: coinConfig.type, qtd: numCoins }
      });

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Você enviou ${numCoins} ${coinConfig.label}(s) para ${recipient.name}!`, 'success');

      setAmount('1');
      setReason('');
      setRecipientId('');

    } catch (error) {
      showToast('Erro ao processar envio.', 'error');
    } finally {
