import React, { useState } from 'react';
import { User, UserStatus, Role, Capability, RewardItem } from '../types';
import { saveDB, addAuditLog } from '../store';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS' | 'CONFIG' | 'LOGS'>('USERS');

  const updateUserStatus = (u: User, status: UserStatus) => {
    const userInDb = db.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      addAuditLog(db, {
        actorUserId: user.id,
        action: 'USER_STATUS_CHANGE',
        entityType: 'USER',
        entityId: u.id,
        details: { status }
      });
      saveDB(db);
      onRefreshDB();
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const userInDb = db.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      if (userInDb.capabilities.includes(cap)) {
        userInDb.capabilities = userInDb.capabilities.filter((c: Capability) => c !== cap);
      } else {
        // Limpar capacidades de cargo ao selecionar uma nova para evitar conflito de moedas
        const jobCaps = [
          Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, 
          Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO
        ];
        if (jobCaps.includes(cap)) {
           userInDb.capabilities = userInDb.capabilities.filter(c => !jobCaps.includes(c));
        }
        userInDb.capabilities.push(cap);
      }
      saveDB(db);
      onRefreshDB();
    }
  };

  const handleCreateItem = () => {
    const name = prompt('Nome do brinde:');
    if (!name) return;
    const cost = Number(prompt('Custo em tampinhas:'));
    const stock = Number(prompt('Estoque inicial:'));
    const category = prompt('Categoria:', 'Geral') || 'Geral';

    const newItem: RewardItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      description: 'Descrição automática',
      imageUrl: `https://picsum.photos/400/300?random=${Math.random()}`,
      cost,
      stock,
      category,
      isActive: true
    };

    db.rewardItems.push(newItem);
    saveDB(db);
    onRefreshDB();
  };

  const capabilityLabels: Record<Capability, string> = {
    [Capability.RECEIVE_ONLY]: 'Somente Recebe',
    [Capability.LEADERSHIP]: 'Liderança (Padrão)',
    [Capability.APPROVE_PURCHASES]: 'Aprovador Extra',
    [Capability.ADMIN]: 'Admin Master',
    [Capability.OPERADOR]: 'Operador',
    [Capability.SUPERVISOR_COORDENADOR]: 'Supervisor/Coord.',
    [Capability.GERENTE_AREA]: 'Gerente Área',
    [Capability.GERENTE_FABRIL]: 'Gerente Fabril',
    [Capability.GENTE_GESTAO]: 'Gente & Gestão'
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 rounded-full border border-yellow-500 flex flex-col items-center justify-center bg-black">
              <span className="text-yellow-500 font-black italic text-[8px] leading-none">SUPPLY</span>
              <div className="w-6 h-[1px] bg-white my-0.5 opacity-50"></div>
           </div>
           <div>
             <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Configurações</h1>
             <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1">Gerencie cargos e tipos de moedas.</p>
           </div>
        </div>
      </header>

      <div className="flex gap-4 border-b border-zinc-800 overflow-x-auto">
        <button onClick={() => setActiveTab('USERS')} className={`px-4 py-3 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap ${activeTab === 'USERS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Usuários & Cargos</button>
        <button onClick={() => setActiveTab('ITEMS')} className={`px-4 py-3 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap ${activeTab === 'ITEMS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Brindes</button>
        <button onClick={() => setActiveTab('LOGS')} className={`px-4 py-3 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap ${activeTab === 'LOGS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Auditoria</button>
      </div>

      {activeTab === 'USERS' && (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[1000px]">
              <thead className="bg-black/40">
                <tr>
                  <th className="px-6 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">Colaborador</th>
                  <th className="px-6 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">Atribuição de Cargo (Define Moeda)</th>
                  <th className="px-6 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-right">Controle</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-800">
                {db.users.map((u: User) => (
                  <tr key={u.id} className="hover:bg-white/5 transition-colors">
                    <td className="px-6 py-6">
                      <p className="font-black text-white uppercase italic tracking-tighter">{u.name}</p>
