                          >
                            {capabilityLabels[cap]}
                          </button>
                        ))}
                      </div>
                    </td>
                    <td className="px-6 py-6 text-right space-x-2">
                      {u.status === UserStatus.PENDING && (
                        <button 
                          onClick={() => updateUserStatus(u, UserStatus.ACTIVE)} 
                          className="w-10 h-10 bg-emerald-500 text-black rounded-xl hover:bg-emerald-400 shadow-lg shadow-emerald-500/10" 
                        >
                          <i className="fa-solid fa-check"></i>
                        </button>
                      )}
                      <button 
                        onClick={() => updateUserStatus(u, u.status === UserStatus.BLOCKED ? UserStatus.ACTIVE : UserStatus.BLOCKED)} 
                        className={`w-10 h-10 rounded-xl transition-all inline-flex items-center justify-center ${u.status === UserStatus.BLOCKED ? 'bg-yellow-500 text-black' : 'bg-zinc-800 text-zinc-500 hover:text-rose-500'}`}
                      >
                        <i className={`fa-solid ${u.status === UserStatus.BLOCKED ? 'fa-unlock' : 'fa-lock'}`}></i>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Outras abas (ITEMS, LOGS) mantidas idênticas ao fluxo anterior... */}
      {activeTab === 'ITEMS' && (
        <div className="space-y-4">
