const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS' | 'LOGS'>('USERS');

  const updateUserStatus = (u: User, status: UserStatus) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'USER_STATUS_CHANGE',
        entityType: 'USER',
        entityId: u.id,
        details: { status }
      });
      saveDB(currentDb);
      onRefreshDB();
      showToast(`Status do usuário atualizado para ${status}`, 'success');
