        <button onClick={() => setActiveTab('ITEMS')} className={`px-4 py-3 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap ${activeTab === 'ITEMS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Catálogo</button>
        <button onClick={() => setActiveTab('LOGS')} className={`px-4 py-3 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 whitespace-nowrap ${activeTab === 'LOGS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Auditoria</button>
      </div>

      {activeTab === 'USERS' && (
