import React, { useState, useMemo } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');

  // Cálculos do Dashboard Econômico
  const economicData = useMemo(() => {
    // 1. Valor total do estoque (Soma de: custo do item * quantidade em estoque)
    const totalStockValue = db.rewardItems.reduce((acc: number, item: RewardItem) => acc + (item.cost * item.stock), 0);

    // 2. Pontos distribuídos aos Operadores (Saldo atual de todos os usuários)
    const totalDistributedPoints = db.wallets.reduce((acc: number, w: Wallet) => acc + w.balance, 0);

    // 3. Capacidade de doação (Simulação baseada no estoque disponível vs distribuído)
    const balanceGap = totalStockValue - totalDistributedPoints;

    return {
      totalStockValue,
      totalDistributedPoints,
      balanceGap
    };
  }, [db.rewardItems, db.wallets]);

  const updateUserStatus = (u: User, status: UserStatus) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'USER_STATUS_CHANGE',
        entityType: 'USER',
        entityId: u.id,
