    if (userInDb) {
      const jobCaps = [
        Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, 
        Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO
      ];
      if (userInDb.capabilities.includes(cap)) {
        userInDb.capabilities = userInDb.capabilities.filter((c: Capability) => c !== cap);
      } else {
        if (jobCaps.includes(cap)) userInDb.capabilities = userInDb.capabilities.filter(c => !jobCaps.includes(c));
        userInDb.capabilities.push(cap);
      }
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const updateStock = (itemId: string, newStock: number) => {
    const currentDb = getDB();
    const item = currentDb.rewardItems.find((i: any) => i.id === itemId);
