        <button onClick={() => setActiveTab('USERS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'USERS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Colaboradores</button>
