/**
 * Função para buscar o estado global do banco de dados no Supabase.
 * Assume-se uma tabela 'app_state' com id=1 e coluna 'data' (JSONB).
 */
export const getDB = (): DB => {
  const data = localStorage.getItem('tampinhas_digital_v1');
  if (!data) return INITIAL_DB;
  try {
    return JSON.parse(data);
  } catch (e) {
    return INITIAL_DB;
  }
};

/**
 * Salva o estado atual. 
 * Mantemos o localStorage como 'cache' de fallback, 
 * mas a lógica principal deve invocar o Supabase via App.tsx.
 */
export const saveDB = (db: DB) => {
  localStorage.setItem('tampinhas_digital_v1', JSON.stringify(db));
};

export const addAuditLog = (db: DB, log: Omit<AuditLog, 'id' | 'createdAt'>) => {
