  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    setToast({ message, type });
  }, []);

  // Função para salvar o estado completo no Supabase
  const syncWithCloud = useCallback(async (data: any) => {
    // 1. Salva no localStorage para feedback instantâneo e offline parcial
    saveDB(data);

    // 2. Persiste no Supabase
    try {
      const { error } = await supabase
        .from('app_state')
        .upsert({ 
          id: 1, 
          content: data, 
          updated_at: new Date().toISOString() 
        }, { onConflict: 'id' });

      if (error) throw error;
      console.log('Dados sincronizados com sucesso no Supabase.');
