    localStorage.removeItem('current_user_id');
    setView('LOGIN');
  };

  // Função central para disparar atualizações e salvar na nuvem
  const refreshDB = useCallback(() => {
    const current = getDB();
    setDb(current);
    syncWithCloud(current);
  }, [syncWithCloud]);

  const userWallet = useMemo(() => {
