    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 };
  }, [user, db.wallets]);

  if (isLoading) return (
    <div className="min-h-screen bg-black flex flex-col items-center justify-center">
