const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImdoZ3lpc2NuemN3b2tpbGxubG94Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUzNzgyMjYsImV4cCI6MjA4MDk1NDIyNn0.1qzhIJ7A0pfxl8cuHTqFnCAZ7cMIICfhuYKlfhkhchU';
const supabase = createClient(supabaseUrl, supabaseKey);

const App: React.FC = () => {
  const [db, setDb] = useState(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    setToast({ message, type });
  }, []);

  // Função para salvar o estado completo no Supabase
  const syncWithCloud = useCallback(async (data: any) => {
    saveDB(data); // Cache local rápido
    try {
      const { error } = await supabase
        .from('app_state')
        .upsert({ 
          id: 1, 
          content: data, 
          updated_at: new Date().toISOString() 
        }, { onConflict: 'id' });

      if (error) throw error;
      console.log('Dados sincronizados com sucesso no Supabase.');
    } catch (err) {
      console.error('Falha na sincronização com Supabase:', err);
    }
  }, []);

  // Busca inicial: Prioriza Supabase, senão usa LocalStorage, senão INITIAL_DB
  useEffect(() => {
    const initData = async () => {
      setIsLoading(true);
      try {
        const { data, error } = await supabase
          .from('app_state')
          .select('content')
          .eq('id', 1)
          .maybeSingle();

        if (!error && data && data.content && Object.keys(data.content).length > 0) {
          setDb(data.content);
          saveDB(data.content);
        } else {
          // Se falhar a nuvem ou a tabela estiver vazia, tenta o local
          const local = getDB();
          setDb(local);
        }
      } catch (err) {
        console.warn('Erro ao conectar ao Supabase, carregando local...', err);
        setDb(getDB());
      } finally {
        setIsLoading(false);
      }
    };

    initData();
  }, []);

  // Persistência da sessão de login
  useEffect(() => {
    if (!isLoading) {
      const savedUserId = localStorage.getItem('current_user_id');
      if (savedUserId) {
        const dbUser = db.users.find(u => u.id === savedUserId);
        if (dbUser && dbUser.status === UserStatus.ACTIVE) {
          setUser(dbUser);
          setView('DASHBOARD');
        }
      }
    }
  }, [isLoading, db.users]);

  const handleLogin = (u: User) => {
    if (u.status === UserStatus.PENDING) {
      showToast('Acesso negado: cadastro pendente.', 'warning');
      return;
    }
    if (u.status === UserStatus.BLOCKED) {
      showToast('Conta bloqueada.', 'error');
      return;
    }
    setUser(u);
    localStorage.setItem('current_user_id', u.id);
    setView('DASHBOARD');
    showToast(`Bem-vindo, ${u.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user_id');
    setView('LOGIN');
  };

  // Função central para disparar atualizações e salvar na nuvem
  const refreshDB = useCallback(() => {
    const current = getDB();
    setDb(current);
    syncWithCloud(current);
  }, [syncWithCloud]);

  const userWallet = useMemo(() => {
    if (!user) return { userId: '', balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 };
    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0, goldCoins: 0, silverCoins: 0, bronzeCoins: 0 };
  }, [user, db.wallets]);

  if (isLoading) return (
    <div className="min-h-screen bg-black flex flex-col items-center justify-center">
      <div className="tampinha-container mb-8 scale-75">
        <div className="tampinha-serrilha animate-spin-slow"></div>
        <div className="tampinha-fundo-preto">
          <span className="text-yellow-500 font-black italic text-xl">S</span>
        </div>
      </div>
      <p className="text-yellow-500 font-black uppercase tracking-widest text-[10px] animate-pulse italic">Conectando ao Banco de Dados Supply...</p>
    </div>
  );

  if (view === 'LOGIN') return (
    <>
      <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  if (view === 'REGISTER') return (
    <>
      <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  return (
    <div className="flex min-h-screen bg-black">
      <Sidebar currentView={view} setView={setView} capabilities={user?.capabilities || []} />
      <div className="flex-1 flex flex-col min-w-0">
        <Topbar user={user} wallet={userWallet} onLogout={handleLogout} />
        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-black">
          <div className="max-w-7xl mx-auto">
            {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
            {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
            {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
          </div>
        </main>
      </div>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');
  const [selectedUserForCarga, setSelectedUserForCarga] = useState<User | null>(null);
  const [cargaAmount, setCargaAmount] = useState<number>(0);

  // Cálculos do Dashboard Econômico
  const economicData = useMemo(() => {
    const totalStockValue = db.rewardItems.reduce((acc: number, item: RewardItem) => acc + (item.cost * item.stock), 0);
    const totalDistributedPoints = db.wallets.reduce((acc: number, w: Wallet) => acc + w.balance, 0);
    const balanceGap = totalStockValue - totalDistributedPoints;

    return { totalStockValue, totalDistributedPoints, balanceGap };
  }, [db.rewardItems, db.wallets]);

  const updateUserStatus = (u: User, status: UserStatus) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'USER_STATUS_CHANGE',
        entityType: 'USER',
        entityId: u.id,
        details: { status }
      });
      saveDB(currentDb);
      onRefreshDB();
      showToast(`Status de ${u.name} atualizado.`, 'success');
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobCaps = [
        Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, 
        Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO
      ];
      if (userInDb.capabilities.includes(cap)) {
        userInDb.capabilities = userInDb.capabilities.filter((c: Capability) => c !== cap);
      } else {
        if (jobCaps.includes(cap)) userInDb.capabilities = userInDb.capabilities.filter(c => !jobCaps.includes(c));
        userInDb.capabilities.push(cap);
      }
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const handleCargaMoedas = () => {
    if (!selectedUserForCarga || cargaAmount <= 0) return;

    // Determinar peso da moeda do usuário alvo
    let weight = 1;
    let coinType = CoinType.BRONZE;

    if (selectedUserForCarga.capabilities.includes(Capability.ADMIN) || selectedUserForCarga.capabilities.includes(Capability.GERENTE_FABRIL)) {
      weight = 3;
      coinType = CoinType.GOLD;
    } else if (selectedUserForCarga.capabilities.includes(Capability.GERENTE_AREA)) {
      weight = 2;
      coinType = CoinType.SILVER;
    }

    const totalPointsNeeded = cargaAmount * weight;

    if (totalPointsNeeded > economicData.balanceGap) {
      showToast(`Estoque insuficiente! Você precisa de ${totalPointsNeeded} pts, mas tem apenas ${economicData.balanceGap} pts disponíveis.`, 'error');
      return;
    }

    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === selectedUserForCarga.id);

    if (wallet) {
      wallet.balance += totalPointsNeeded;
      if (coinType === CoinType.GOLD) wallet.goldCoins += cargaAmount;
      if (coinType === CoinType.SILVER) wallet.silverCoins += cargaAmount;
      if (coinType === CoinType.BRONZE) wallet.bronzeCoins += cargaAmount;

      currentDb.transactions.unshift({
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPointsNeeded,
        coinType: coinType,
        fromUserId: 'SYSTEM',
        toUserId: selectedUserForCarga.id,
        reason: 'Carga Administrativa de Moedas',
        category: 'Distribuição',
        createdAt: new Date().toISOString(),
        createdBy: user.id
      });

      addAuditLog(currentDb, {
        actorUserId: user.id,
        action: 'ADMIN_RECHARGE',
        entityType: 'USER',
        entityId: selectedUserForCarga.id,
        details: { qtd: cargaAmount, pontos: totalPointsNeeded, tipo: coinType }
      });

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Carga de ${cargaAmount} moedas realizada para ${selectedUserForCarga.name}`, 'success');
      setSelectedUserForCarga(null);
      setCargaAmount(0);
    }
  };

  const updateStock = (itemId: string, newStock: number) => {
    const currentDb = getDB();
    const item = currentDb.rewardItems.find((i: any) => i.id === itemId);
    if (item) {
      item.stock = newStock;
      saveDB(currentDb);
      onRefreshDB();
      showToast(`Estoque de ${item.name} atualizado.`, 'success');
    }
  };

  const handleCreateItem = () => {
    const name = prompt('Nome do brinde:');
    if (!name) return;
    const cost = Number(prompt('Custo em moedas:'));
    const stock = Number(prompt('Estoque inicial:'));
    const category = prompt('Categoria (Vestuário, Eletrônicos, etc):', 'Geral') || 'Geral';

    const currentDb = getDB();
    const newItem: RewardItem = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      name,
      description: 'Item adicionado via painel administrativo.',
      imageUrl: `https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&q=80&w=400`,
      cost,
      stock,
      category,
      isActive: true
    };

    currentDb.rewardItems.push(newItem);
    saveDB(currentDb);
    onRefreshDB();
    showToast('Brinde adicionado com sucesso!', 'success');
  };

  const sortedUsers = [...db.users].sort((a, b) => {
    if (a.status === UserStatus.PENDING && b.status !== UserStatus.PENDING) return -1;
    return 0;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Painel de Controle</h1>
        <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1 italic">Gestão econômica e de colaboradores.</p>
      </header>

      {/* DASHBOARD ECONÔMICO */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className={`p-8 rounded-[2.5rem] border ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Saúde do Estoque</p>
          <div className="flex items-end gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
              {economicData.balanceGap}
            </span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Disponíveis</span>
          </div>
          <p className="text-[9px] text-zinc-500 mt-2 font-medium">Comparativo entre Valor em Estoque vs. Moedas em mãos.</p>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Moedas em Circulação</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-white italic tracking-tighter">{economicData.totalDistributedPoints}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Totais</span>
          </div>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Valor Patrimonial</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-yellow-500 italic tracking-tighter">{economicData.totalStockValue}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Reais</span>
          </div>
        </div>
      </div>

      <div className="flex gap-4 border-b border-zinc-800">
        <button onClick={() => setActiveTab('USERS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'USERS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Colaboradores</button>
        <button onClick={() => setActiveTab('ITEMS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'ITEMS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Gestão de Estoque</button>
      </div>

      {activeTab === 'USERS' && (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[2.5rem] overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-black/40">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">Colaborador</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-center">Atribuição</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-800">
              {sortedUsers.map((u: User) => {
                const canReceiveCoins = u.capabilities.some(c => [
                  Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN
                ].includes(c));

                return (
                  <tr key={u.id} className="hover:bg-white/5 transition-colors">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                        {u.status === UserStatus.PENDING && <span className="w-2 h-2 rounded-full bg-yellow-500 animate-pulse"></span>}
                        <div>
                          <p className="font-black text-white uppercase italic tracking-tighter">{u.name}</p>
                          <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">ID: {u.corporateId}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2 justify-center">
                        {[Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO].map(cap => (
                          <button 
                            key={cap}
                            onClick={() => toggleCapability(u, cap)}
                            className={`px-3 py-1.5 rounded-xl text-[8px] border font-black uppercase tracking-widest transition-all ${u.capabilities.includes(cap) ? 'bg-yellow-500 text-black border-yellow-500' : 'bg-black text-zinc-600 border-zinc-800'}`}
                          >
                            {cap.split('_').join(' ')}
                          </button>
                        ))}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center justify-end gap-2">
                        {canReceiveCoins && u.status === UserStatus.ACTIVE && (
                          <button 
                            onClick={() => setSelectedUserForCarga(u)}
                            className="bg-emerald-500/20 text-emerald-500 border border-emerald-500/30 p-2.5 rounded-xl hover:bg-emerald-500 hover:text-black transition-all"
                            title="Distribuir Moedas para Doação"
                          >
                            <i className="fa-solid fa-coins"></i>
                          </button>
                        )}

                        {u.status === UserStatus.PENDING ? (
                          <button onClick={() => updateUserStatus(u, UserStatus.ACTIVE)} className="bg-emerald-500 text-black px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest">Ativar</button>
                        ) : (
                          <button onClick={() => updateUserStatus(u, u.status === UserStatus.BLOCKED ? UserStatus.ACTIVE : UserStatus.BLOCKED)} className={`w-10 h-10 rounded-xl flex items-center justify-center ${u.status === UserStatus.BLOCKED ? 'bg-yellow-500 text-black' : 'bg-zinc-800 text-zinc-500 hover:text-white'}`}>
                            <i className={`fa-solid ${u.status === UserStatus.BLOCKED ? 'fa-unlock' : 'fa-lock'}`}></i>
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* MODAL DE CARGA DE MOEDAS */}
      {selectedUserForCarga && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="text-center mb-8">
              <div className="w-16 h-16 bg-yellow-500 rounded-full flex items-center justify-center mx-auto mb-4 text-black text-2xl">
                <i className="fa-solid fa-bolt"></i>
              </div>
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">Carga de Moedas</h3>
              <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-1">Destinatário: {selectedUserForCarga.name}</p>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Quantidade de Moedas</label>
                <input 
                  type="number"
                  autoFocus
                  className="w-full p-5 bg-black border border-zinc-800 text-white text-3xl font-black rounded-3xl text-center focus:border-yellow-500 outline-none"
                  value={cargaAmount || ''}
                  onChange={e => setCargaAmount(Number(e.target.value))}
                />
                <div className="flex justify-between p-3 bg-black/50 rounded-2xl border border-zinc-800/50 mt-4">
                  <div>
                    <p className="text-[8px] font-black text-zinc-500 uppercase">Impacto no Estoque</p>
                    <p className="text-xl font-black text-rose-500 italic">
                      -{cargaAmount * (selectedUserForCarga.capabilities.includes(Capability.GERENTE_FABRIL) || selectedUserForCarga.capabilities.includes(Capability.ADMIN) ? 3 : selectedUserForCarga.capabilities.includes(Capability.GERENTE_AREA) ? 2 : 1)} pts
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-zinc-500 uppercase">Disponível Agora</p>
                    <p className="text-xl font-black text-white italic">{economicData.balanceGap} pts</p>
                  </div>
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setSelectedUserForCarga(null)}
                  className="flex-1 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest text-zinc-500 hover:bg-zinc-800 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleCargaMoedas}
                  className="flex-[2] py-4 bg-yellow-500 text-black rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-yellow-400 shadow-lg shadow-yellow-500/10 active:scale-95 transition-all"
                >
                  Confirmar Carga
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* GESTÃO DE ITENS (Sem alterações solicitadas aqui, mantendo consistência) */}
      {activeTab === 'ITEMS' && (
        <div className="space-y-6">
          <div className="flex justify-end">
            <button onClick={handleCreateItem} className="bg-yellow-500 text-black px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-yellow-400 shadow-xl">Cadastrar Novo Brinde</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {db.rewardItems.map((item: RewardItem) => (
              <div key={item.id} className="bg-zinc-900/40 p-6 rounded-[2rem] border border-zinc-800 space-y-4">
                <div className="flex items-center gap-4">
                  <img src={item.imageUrl} className="w-16 h-16 rounded-2xl object-cover grayscale" />
                  <div className="flex-1">
                    <h4 className="font-black text-white uppercase italic tracking-tighter leading-none">{item.name}</h4>
                    <p className="text-[10px] text-zinc-500 font-bold mt-1 uppercase">{item.category}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-zinc-600 uppercase">Custo</p>
                    <p className="text-xl font-black text-yellow-500 italic">{item.cost} t.</p>
                  </div>
                </div>

                <div className="pt-4 border-t border-zinc-800 flex items-center justify-between">
                  <div className="flex flex-col">
                    <label className="text-[8px] font-black text-zinc-500 uppercase tracking-widest mb-1">Estoque Atual</label>
                    <div className="flex items-center gap-3">
                      <button onClick={() => updateStock(item.id, Math.max(0, item.stock - 1))} className="w-8 h-8 rounded-lg bg-black border border-zinc-800 flex items-center justify-center text-white hover:border-yellow-500">-</button>
                      <span className="text-xl font-black text-white italic min-w-[30px] text-center">{item.stock}</span>
                      <button onClick={() => updateStock(item.id, item.stock + 1)} className="w-8 h-8 rounded-lg bg-black border border-zinc-800 flex items-center justify-center text-white hover:border-yellow-500">+</button>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-zinc-600 uppercase">Total Patrimonial</p>
                    <p className="text-sm font-black text-white">{item.cost * item.stock} t.</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

export enum UserStatus {
  PENDING = 'PENDING',
  ACTIVE = 'ACTIVE',
  BLOCKED = 'BLOCKED'
}

export enum Role {
  USER = 'USER',
  APPROVER = 'APPROVER',
  ADMIN = 'ADMIN'
}

export enum Capability {
  RECEIVE_ONLY = 'SOMENTE_RECEBE',
  LEADERSHIP = 'LIDERANÇA',
  APPROVE_PURCHASES = 'APROVAR_RESGATES',
  ADMIN = 'ADMINISTRADOR',
  OPERADOR = 'OPERADOR',
  SUPERVISOR_COORDENADOR = 'SUPERVISOR_COORDENADOR',
  GERENTE_AREA = 'GERENTE_AREA',
  GERENTE_FABRIL = 'GERENTE_FABRIL',
  GENTE_GESTAO = 'GENTE_GESTAO'
}

export interface User {
  id: string;
  corporateId: string;
  name: string;
  passwordHash: string;
  status: UserStatus;
  roles: Role[];
  capabilities: Capability[];
  createdAt: string;
}

export interface Wallet {
  userId: string;
  balance: number; // Saldo PESSOAL para gastar na loja
  // Carteira de DOAÇÃO (Verba recebida do Admin)
  donatableGold: number;
  donatableSilver: number;
  donatableBronze: number;
}

export enum TransactionType {
  CREDIT = 'CREDIT',
  DEBIT = 'DEBIT'
}

export enum CoinType {
  BRONZE = 'BRONZE',
  SILVER = 'SILVER',
  GOLD = 'GOLD'
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number; 
  coinType?: CoinType; 
  fromUserId: string | 'SYSTEM';
  toUserId: string;
  reason: string;
  category: string;
  createdAt: string;
  createdBy: string;
  isDonationVerba?: boolean; // Flag para diferenciar carga de verba de reconhecimento real
}

export interface RewardItem {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  cost: number;
  stock: number;
  category: string;
  isActive: boolean;
}

export enum OrderStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  ADJUSTMENT_REQUESTED = 'ADJUSTMENT_REQUESTED',
  DELIVERED = 'DELIVERED'
}

export interface Order {
  id: string;
  userId: string;
  status: OrderStatus;
  totalCost: number;
  createdAt: string;
  updatedAt: string;
  items: OrderItem[];
  note?: string;
  approverId?: string;
}

export interface OrderItem {
  itemId: string;
  qty: number;
  costEach: number;
}

export interface AuditLog {
  id: string;
  actorUserId: string;
  action: string;
  entityType: string;
  entityId: string;
  details: any;
  createdAt: string;
}

import React, { useState, useMemo } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');
  const [selectedUserForCarga, setSelectedUserForCarga] = useState<User | null>(null);
  const [cargaAmount, setCargaAmount] = useState<number>(0);

  const economicData = useMemo(() => {
    const totalStockValue = db.rewardItems.reduce((acc: number, item: RewardItem) => acc + (item.cost * item.stock), 0);
    // Pontos em circulação = Saldos Pessoais + Saldos de Doação (convertidos em peso)
    const personalPoints = db.wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = db.wallets.reduce((acc: number, w: Wallet) => {
      return acc + (w.donatableGold * 3) + (w.donatableSilver * 2) + (w.donatableBronze * 1);
    }, 0);

    const totalDistributedPoints = personalPoints + donationPoints;
    const balanceGap = totalStockValue - totalDistributedPoints;

    return { totalStockValue, totalDistributedPoints, balanceGap };
  }, [db.rewardItems, db.wallets]);

  const handleCargaMoedas = () => {
    if (!selectedUserForCarga || cargaAmount <= 0) return;

    let weight = 1;
    let coinType = CoinType.BRONZE;

    if (selectedUserForCarga.capabilities.includes(Capability.ADMIN) || selectedUserForCarga.capabilities.includes(Capability.GERENTE_FABRIL)) {
      weight = 3;
      coinType = CoinType.GOLD;
    } else if (selectedUserForCarga.capabilities.includes(Capability.GERENTE_AREA)) {
      weight = 2;
      coinType = CoinType.SILVER;
    }

    const totalPointsNeeded = cargaAmount * weight;

    if (totalPointsNeeded > economicData.balanceGap) {
      showToast(`Estoque insuficiente! Você precisa de ${totalPointsNeeded} pts, mas o sistema tem apenas ${economicData.balanceGap} pts livres.`, 'error');
      return;
    }

    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === selectedUserForCarga.id);

    if (wallet) {
      // IMPORTANTE: Incrementa o saldo de DOAÇÃO, não o balance (pessoal)
      if (coinType === CoinType.GOLD) wallet.donatableGold = (wallet.donatableGold || 0) + cargaAmount;
      if (coinType === CoinType.SILVER) wallet.donatableSilver = (wallet.donatableSilver || 0) + cargaAmount;
      if (coinType === CoinType.BRONZE) wallet.donatableBronze = (wallet.donatableBronze || 0) + cargaAmount;

      currentDb.transactions.unshift({
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPointsNeeded,
        coinType: coinType,
        fromUserId: 'SYSTEM',
        toUserId: selectedUserForCarga.id,
        reason: 'Carga de Verba para Distribuição',
        category: 'Verba Administrativa',
        createdAt: new Date().toISOString(),
        createdBy: user.id,
        isDonationVerba: true
      });

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Verba de ${cargaAmount} moedas de ${coinType} carregada para ${selectedUserForCarga.name}`, 'success');
      setSelectedUserForCarga(null);
      setCargaAmount(0);
    }
  };

  const updateUserStatus = (u: User, status: UserStatus) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobCaps = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (userInDb.capabilities.includes(cap)) {
        userInDb.capabilities = userInDb.capabilities.filter((c: Capability) => c !== cap);
      } else {
        if (jobCaps.includes(cap)) userInDb.capabilities = userInDb.capabilities.filter(c => !jobCaps.includes(c));
        userInDb.capabilities.push(cap);
      }
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const updateStock = (itemId: string, newStock: number) => {
    const currentDb = getDB();
    const item = currentDb.rewardItems.find((i: any) => i.id === itemId);
    if (item) {
      item.stock = newStock;
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const sortedUsers = [...db.users].sort((a, b) => (a.status === UserStatus.PENDING ? -1 : 0));

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Gestão Econômica</h1>
        <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1 italic">Controle de Verba e Colaboradores.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className={`p-8 rounded-[2.5rem] border ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão</p>
          <div className="flex items-end gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
              {economicData.balanceGap}
            </span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Disponíveis</span>
          </div>
          <p className="text-[9px] text-zinc-500 mt-2 font-medium">Margem segura baseada no estoque real de brindes.</p>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo Circulante</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-white italic tracking-tighter">{economicData.totalDistributedPoints}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Emitidos</span>
          </div>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio de Brindes</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-yellow-500 italic tracking-tighter">{economicData.totalStockValue}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Reais</span>
          </div>
        </div>
      </div>

      <div className="flex gap-4 border-b border-zinc-800">
        <button onClick={() => setActiveTab('USERS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'USERS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Colaboradores</button>
        <button onClick={() => setActiveTab('ITEMS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'ITEMS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Estoque</button>
      </div>

      {activeTab === 'USERS' && (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[2.5rem] overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-black/40">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">Colaborador</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-center">Perfil</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-right">Ações de Verba</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-800">
              {sortedUsers.map((u: User) => {
                const isLeader = u.capabilities.some(c => [Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN].includes(c));
                return (
                  <tr key={u.id} className="hover:bg-white/5 transition-colors">
                    <td className="px-8 py-6">
                      <p className="font-black text-white uppercase italic tracking-tighter">{u.name}</p>
                      <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">ID: {u.corporateId}</p>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2 justify-center">
                        {[Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO].map(cap => (
                          <button key={cap} onClick={() => toggleCapability(u, cap)} className={`px-3 py-1.5 rounded-xl text-[8px] border font-black uppercase tracking-widest transition-all ${u.capabilities.includes(cap) ? 'bg-yellow-500 text-black border-yellow-500' : 'bg-black text-zinc-600 border-zinc-800'}`}>{cap.split('_').join(' ')}</button>
                        ))}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center justify-end gap-2">
                        {isLeader && u.status === UserStatus.ACTIVE && (
                          <button onClick={() => setSelectedUserForCarga(u)} className="bg-emerald-500/20 text-emerald-500 border border-emerald-500/30 p-2.5 rounded-xl hover:bg-emerald-500 hover:text-black transition-all">
                            <i className="fa-solid fa-bolt mr-2"></i> CARREGAR VERBA
                          </button>
                        )}
                        <button onClick={() => updateUserStatus(u, u.status === UserStatus.BLOCKED ? UserStatus.ACTIVE : UserStatus.BLOCKED)} className="w-10 h-10 rounded-xl bg-zinc-800 text-zinc-500 flex items-center justify-center hover:text-white">
                          <i className={`fa-solid ${u.status === UserStatus.BLOCKED ? 'fa-unlock' : 'fa-lock'}`}></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {selectedUserForCarga && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter text-center mb-6">Distribuir Verba de Gestão</h3>
            <p className="text-center text-[10px] text-zinc-500 font-bold uppercase mb-8">Líder: {selectedUserForCarga.name}</p>
            <div className="space-y-6">
              <input type="number" autoFocus className="w-full p-5 bg-black border border-zinc-800 text-white text-3xl font-black rounded-3xl text-center outline-none focus:border-yellow-500" value={cargaAmount || ''} onChange={e => setCargaAmount(Number(e.target.value))} />
              <div className="bg-black/50 p-4 rounded-2xl border border-zinc-800/50">
                 <p className="text-[8px] font-black text-zinc-500 uppercase mb-1">Peso da Verba</p>
                 <p className="text-xl font-black text-emerald-500 italic">Verba para Redistribuição</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setSelectedUserForCarga(null)} className="flex-1 py-4 text-zinc-500 font-black text-[10px] uppercase">Cancelar</button>
                <button onClick={handleCargaMoedas} className="flex-[2] py-4 bg-yellow-500 text-black rounded-2xl font-black text-[10px] uppercase tracking-widest">Liberar Moedas</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

import React, { useState, useMemo } from 'react';
import { User, TransactionType, Transaction, Capability, CoinType, Wallet } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [recipientId, setRecipientId] = useState('');
  const [amount, setAmount] = useState<string>('1');
  const [reason, setReason] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const wallet = useMemo(() => {
    return db.wallets.find((w: Wallet) => w.userId === user.id) || { donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
  }, [user.id, db.wallets]);

  const coinConfig = useMemo(() => {
    if (user.capabilities.includes(Capability.ADMIN) || user.capabilities.includes(Capability.GERENTE_FABRIL)) {
      return { type: CoinType.GOLD, weight: 3, label: 'Moeda de Ouro', color: 'text-yellow-500', stock: wallet.donatableGold || 0 };
    }
    if (user.capabilities.includes(Capability.GERENTE_AREA)) {
      return { type: CoinType.SILVER, weight: 2, label: 'Moeda de Prata', color: 'text-zinc-400', stock: wallet.donatableSilver || 0 };
    }
    return { type: CoinType.BRONZE, weight: 1, label: 'Moeda de Bronze', color: 'text-orange-600', stock: wallet.donatableBronze || 0 };
  }, [user.capabilities, wallet]);

  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    const numCoins = Number(amount);
    if (numCoins > coinConfig.stock) {
      showToast(`Você não possui verba suficiente. Saldo disponível: ${coinConfig.stock} moedas.`, 'error');
      return;
    }

    if (!recipientId || numCoins <= 0 || !reason.trim()) {
      showToast('Preencha todos os campos corretamente.', 'warning');
      return;
    }

    try {
      setIsSubmitting(true);
      const currentDb = getDB(); 
      const totalPoints = numCoins * coinConfig.weight;

      // 1. Debita da VERBA do doador
      const donorWallet = currentDb.wallets.find((w: any) => w.userId === user.id);
      if (coinConfig.type === CoinType.GOLD) donorWallet.donatableGold -= numCoins;
      if (coinConfig.type === CoinType.SILVER) donorWallet.donatableSilver -= numCoins;
      if (coinConfig.type === CoinType.BRONZE) donorWallet.donatableBronze -= numCoins;

      // 2. Credita no SALDO PESSOAL do receptor
      let recipientWallet = currentDb.wallets.find((w: any) => w.userId === recipientId);
      if (!recipientWallet) {
        currentDb.wallets.push({ userId: recipientId, balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 });
        recipientWallet = currentDb.wallets[currentDb.wallets.length - 1];
      }
      recipientWallet.balance += totalPoints;

      const tx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPoints,
        coinType: coinConfig.type,
        fromUserId: user.id,
        toUserId: recipientId,
        reason: reason.trim(),
        category: `Reconhecimento de Liderança`,
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };
      currentDb.transactions.unshift(tx);

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Sucesso! ${numCoins} moedas enviadas.`, 'success');
      setAmount('1'); setReason(''); setRecipientId('');
    } catch (error) {
      showToast('Erro ao processar envio.', 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-10">
      <header className="flex justify-between items-end">
        <div>
          <p className={`font-black text-[10px] uppercase tracking-[0.3em] mb-1 italic ${coinConfig.color}`}>Sua Verba Disponível: {coinConfig.stock} {coinConfig.label}s</p>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Enviar Reconhecimento</h1>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
        <div className="lg:col-span-3">
          <form onSubmit={handleSubmit} className="bg-zinc-900/40 p-8 rounded-[2.5rem] border border-zinc-800 space-y-6 shadow-2xl relative">
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Colaborador</label>
              <select required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl appearance-none outline-none font-bold" value={recipientId} onChange={e => setRecipientId(e.target.value)}>
                <option value="">Selecione...</option>
                {activeUsers.map((u: User) => (<option key={u.id} value={u.id}>{u.name.toUpperCase()}</option>))}
              </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Qtd de Moedas</label>
                <input type="number" required min="1" max={coinConfig.stock} className={`w-full p-4 bg-black border border-zinc-800 font-black rounded-2xl text-2xl outline-none ${coinConfig.color}`} value={amount} onChange={e => setAmount(e.target.value)} />
              </div>
              <div className="flex flex-col justify-center p-4 bg-black/40 rounded-2xl border border-zinc-800">
                 <p className="text-[10px] font-black text-zinc-500 uppercase">Impacto na Loja:</p>
                 <p className="text-3xl font-black text-white italic tracking-tighter">+{Number(amount) * coinConfig.weight} Pts</p>
              </div>
            </div>
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Motivo</label>
              <textarea required rows={4} className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none" placeholder="Por que este colaborador merece?" value={reason} onChange={e => setReason(e.target.value)}></textarea>
            </div>
            <button type="submit" disabled={isSubmitting || coinConfig.stock === 0} className={`w-full py-5 rounded-2xl font-black text-lg uppercase tracking-widest transition-all ${isSubmitting || coinConfig.stock === 0 ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400'}`}>
              {coinConfig.stock === 0 ? 'SEM VERBA DISPONÍVEL' : 'CONFIRMAR RECONHECIMENTO'}
            </button>
          </form>
        </div>
        <div className="lg:col-span-2 space-y-4">
           <div className="p-8 rounded-[2.5rem] bg-zinc-900 border border-zinc-800">
              <h4 className="font-black text-white uppercase italic text-xl mb-4 tracking-tighter">Como funciona?</h4>
              <p className="text-xs text-zinc-400 font-medium leading-relaxed">
                Você recebeu esta verba do administrador. Quando você doa moedas, elas são convertidas em <strong>Pontos de Compra</strong> para o colaborador, permitindo que ele resgate brindes na loja.
              </p>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Leadership;

import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, TransactionType,
  RewardItem, Order, OrderStatus, AuditLog 
} from './types';

