// Funções auxiliares para persistência
export const getDB = (): DB => {
  const data = localStorage.getItem('tampinhas_digital_v1');
  if (!data) return INITIAL_DB;
  try {
    return JSON.parse(data);
  } catch (e) {
    return INITIAL_DB;
  }
};

export const saveDB = (db: DB) => {
  localStorage.setItem('tampinhas_digital_v1', JSON.stringify(db));
};

export const addAuditLog = (db: DB, log: Omit<AuditLog, 'id' | 'createdAt'>) => {
  const newLog: AuditLog = {
    ...log,
    id: Math.random().toString(36).substr(2, 9),
    createdAt: new Date().toISOString()
  };
  db.auditLogs.unshift(newLog);
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { createClient } from '@supabase/supabase-js';
import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, 
  RewardItem, Order, OrderStatus, TransactionType 
} from './types';
import { getDB, saveDB, INITIAL_DB } from './store';

// Pages & Components
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Store from './pages/Store';
import MyOrders from './pages/MyOrders';
import Leadership from './pages/Leadership';
import Approvals from './pages/Approvals';
import Admin from './pages/Admin';
import Sidebar from './components/Sidebar';
import Topbar from './components/Topbar';
import Toast, { ToastType } from './components/Toast';

// Chaves do Supabase fornecidas pelo usuário
const supabaseUrl = 'https://ghgyiscnzcwokillnlox.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImdoZ3lpc2NuemN3b2tpbGxubG94Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUzNzgyMjYsImV4cCI6MjA4MDk1NDIyNn0.1qzhIJ7A0pfxl8cuHTqFnCAZ7cMIICfhuYKlfhkhchU';
const supabase = createClient(supabaseUrl, supabaseKey);

const App: React.FC = () => {
  const [db, setDb] = useState(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    setToast({ message, type });
  }, []);

  // Função para salvar o estado completo no Supabase
  const syncWithCloud = useCallback(async (data: any) => {
    saveDB(data); // Cache local rápido
    try {
      const { error } = await supabase
        .from('app_state')
        .upsert({ 
          id: 1, 
          content: data, 
          updated_at: new Date().toISOString() 
        }, { onConflict: 'id' });

      if (error) throw error;
      console.log('Dados sincronizados com sucesso no Supabase.');
    } catch (err) {
      console.error('Falha na sincronização com Supabase:', err);
    }
  }, []);

  // Busca inicial: Prioriza Supabase, senão usa LocalStorage, senão INITIAL_DB
  useEffect(() => {
    const initData = async () => {
      setIsLoading(true);
      try {
        const { data, error } = await supabase
          .from('app_state')
          .select('content')
          .eq('id', 1)
          .maybeSingle();

        if (!error && data && data.content && Object.keys(data.content).length > 0) {
          setDb(data.content);
          saveDB(data.content);
        } else {
          // Se falhar a nuvem ou a tabela estiver vazia, tenta o local
          const local = getDB();
          setDb(local);
        }
      } catch (err) {
        console.warn('Erro ao conectar ao Supabase, carregando local...', err);
        setDb(getDB());
      } finally {
        setIsLoading(false);
      }
    };

    initData();
  }, []);

  // Persistência da sessão de login
  useEffect(() => {
    if (!isLoading) {
      const savedUserId = localStorage.getItem('current_user_id');
      if (savedUserId) {
        const dbUser = db.users.find(u => u.id === savedUserId);
        if (dbUser && dbUser.status === UserStatus.ACTIVE) {
          setUser(dbUser);
          setView('DASHBOARD');
        }
      }
    }
  }, [isLoading, db.users]);

  const handleLogin = (u: User) => {
    if (u.status === UserStatus.PENDING) {
      showToast('Acesso negado: cadastro pendente.', 'warning');
      return;
    }
    if (u.status === UserStatus.BLOCKED) {
      showToast('Conta bloqueada.', 'error');
      return;
    }
    setUser(u);
    localStorage.setItem('current_user_id', u.id);
    setView('DASHBOARD');
    showToast(`Bem-vindo, ${u.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user_id');
    setView('LOGIN');
  };

  // Função central para disparar atualizações e salvar na nuvem
  const refreshDB = useCallback(() => {
    const current = getDB();
    setDb(current);
    syncWithCloud(current);
  }, [syncWithCloud]);

  const userWallet = useMemo(() => {
    /* Fix: Return a consistent Wallet object with all mandatory properties defined in types.ts */
    if (!user) return { userId: '', balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
    return db.wallets.find(w => w.userId === user.id) || { userId: user.id, balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
  }, [user, db.wallets]);

  if (isLoading) return (
    <div className="min-h-screen bg-black flex flex-col items-center justify-center">
      <div className="tampinha-container mb-8 scale-75">
        <div className="tampinha-serrilha animate-spin-slow"></div>
        <div className="tampinha-fundo-preto">
          <span className="text-yellow-500 font-black italic text-xl">S</span>
        </div>
      </div>
      <p className="text-yellow-500 font-black uppercase tracking-widest text-[10px] animate-pulse italic">Conectando ao Banco de Dados Supply...</p>
    </div>
  );

  if (view === 'LOGIN') return (
    <>
      <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  if (view === 'REGISTER') return (
    <>
      <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} showToast={showToast} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );

  return (
    <div className="flex min-h-screen bg-black">
      <Sidebar currentView={view} setView={setView} capabilities={user?.capabilities || []} />
      <div className="flex-1 flex flex-col min-w-0">
        <Topbar user={user} wallet={userWallet} onLogout={handleLogout} />
        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-black">
          <div className="max-w-7xl mx-auto">
            {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
            {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
            {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
          </div>
        </main>
      </div>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserStatus, Role, Capability } from '../types';
import { saveDB } from '../store';
import { ToastType } from '../components/Toast';

interface RegisterProps {
  onGoToLogin: () => void;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Register: React.FC<RegisterProps> = ({ onGoToLogin, db, onRefreshDB, showToast }) => {
  const [formData, setFormData] = useState({
    corporateId: '',
    name: '',
    password: '',
    confirmPassword: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      showToast('As senhas digitadas não coincidem.', 'error');
      return;
    }

    if (db.users.some((u: any) => u.corporateId === formData.corporateId)) {
      showToast('Este ID Corporativo já possui uma conta cadastrada.', 'warning');
      return;
    }

    const newUser = {
      id: Math.random().toString(36).substr(2, 9),
      corporateId: formData.corporateId,
      name: formData.name,
      passwordHash: formData.password,
      status: UserStatus.PENDING,
      roles: [Role.USER],
      capabilities: [Capability.RECEIVE_ONLY],
      createdAt: new Date().toISOString()
    };

    db.users.push(newUser);
    /* Fix: Initializing wallet with all required fields from types.ts */
    db.wallets.push({ 
      userId: newUser.id, 
      balance: 0, 
      donatableGold: 0, 
      donatableSilver: 0, 
      donatableBronze: 0 
    });

    saveDB(db);
    onRefreshDB();
    showToast('Cadastro realizado! Aguarde aprovação do Admin.', 'success');
    onGoToLogin();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-black p-4 relative overflow-hidden">
      <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-yellow-500/5 blur-[120px] rounded-full"></div>

      <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-xl border border-zinc-800 rounded-[3rem] shadow-2xl overflow-hidden p-10 animate-in fade-in zoom-in duration-500 relative z-10">
        <div className="text-center mb-10 flex flex-col items-center">
          <div className="w-16 h-16 rounded-full border border-yellow-500 flex flex-col items-center justify-center bg-black mb-4">
            <span className="text-yellow-500 font-black italic text-[9px] leading-none">SUPPLY</span>
            <div className="w-6 h-[1px] bg-white my-0.5 opacity-50"></div>
          </div>
          <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Criar nova conta</h2>
          <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest mt-1">Preencha seus dados para começar.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Nome Completo</label>
            <input 
              type="text" required
              className="w-full px-5 py-3.5 bg-black border border-zinc-800 text-white rounded-2xl focus:outline-none focus:border-yellow-500 transition-all font-bold"
              placeholder="Digite seu nome"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">ID Corporativo</label>
            <input 
              type="text" required
              className="w-full px-5 py-3.5 bg-black border border-zinc-800 text-white rounded-2xl focus:outline-none focus:border-yellow-500 transition-all font-bold"
              placeholder="Ex: 99768009"
              value={formData.corporateId}
              onChange={e => setFormData({...formData, corporateId: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Senha</label>
            <input 
              type="password" required
              className="w-full px-5 py-3.5 bg-black border border-zinc-800 text-white rounded-2xl focus:outline-none focus:border-yellow-500 transition-all font-bold"
              placeholder="••••"
              value={formData.password}
              onChange={e => setFormData({...formData, password: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Confirmar Senha</label>
            <input 
              type="password" required
              className="w-full px-5 py-3.5 bg-black border border-zinc-800 text-white rounded-2xl focus:outline-none focus:border-yellow-500 transition-all font-bold"
              placeholder="••••"
              value={formData.confirmPassword}
              onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
            />
          </div>

          <button 
            type="submit"
            className="w-full bg-yellow-500 text-black py-4 rounded-2xl font-black text-base uppercase tracking-widest hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/10 mt-6 active:scale-[0.98]"
          >
            Finalizar Cadastro
          </button>
        </form>

        <button 
          onClick={onGoToLogin}
          className="w-full mt-6 text-zinc-500 font-bold text-xs uppercase tracking-widest hover:text-white transition-colors"
        >
          Voltar para o Login
        </button>
      </div>
    </div>
  );
};

export default Register;
